'use client';

import { useEffect, useState } from "react";
import Link from "next/link";

type SessionData = {
    dbId?: string | null;
    id?: string | null;
    name?: string | null;
    nickname?: string | null;
    image?: string | null;
    email?: string | null;
    role?: "USER" | "CREATOR" | "ADMIN" | null;
};

type SessionResponse = {
    session: SessionData | null;
};

type AuthStatusProps = {
    myPageColor?: string;
};

export default function AuthStatus({ myPageColor }: AuthStatusProps) {
    const [session, setSession] = useState<SessionData | null>(null);
    const [loaded, setLoaded] = useState(false);

    useEffect(() => {
        let cancelled = false;

        const loadSession = async () => {
            try {
                const response = await fetch("/api/auth/session", { cache: "no-store" });
                if (!response.ok) {
                    return;
                }
                const data = (await response.json()) as SessionResponse;
                if (!cancelled) {
                    setSession(data.session ?? null);
                }
            } finally {
                if (!cancelled) {
                    setLoaded(true);
                }
            }
        };

        loadSession();

        return () => {
            cancelled = true;
        };
    }, []);

    if (!loaded) {
        return null;
    }

    if (!session) {
        return (
            <a
                href="/api/auth/kakao"
                className="text-[13px] font-semibold transition-opacity hover:opacity-70"
                style={{ color: "#3A1D1D" }}
            >
                카카오 로그인
            </a>
        );
    }

    return (
        <div className="flex items-center gap-3">
            <span className="text-[13px] font-semibold" style={{ color: "#3A1D1D" }}>
                {session.nickname ?? "사용자"}
            </span>
            <Link
                href="/mypage"
                className="text-[13px] font-semibold transition-opacity hover:opacity-70"
                style={{ color: myPageColor ?? "#3A1D1D" }}
            >
                마이페이지
            </Link>
            <a
                href="/api/auth/logout"
                className="px-2 py-1 rounded-md text-[12px] font-semibold transition-opacity hover:opacity-70"
                style={{ border: "1px solid #3A1D1D", color: "#3A1D1D" }}
            >
                로그아웃
            </a>
        </div>
    );
}

'use client';

import { useEffect, useState, useCallback } from "react";
import Link from "next/link";
import Image from "next/image";

type SessionData = {
    dbId?: string | null;
    id?: string | null;
    name?: string | null;
    nickname?: string | null;
    image?: string | null;
    avatarUrl?: string | null;
    email?: string | null;
    role?: "USER" | "CREATOR" | "ADMIN" | null;
};

type SessionResponse = {
    session: SessionData | null;
};

type AuthStatusProps = {
    myPageColor?: string;
};

function getAvatarSrc(role: string | null | undefined, avatarUrl: string | null | undefined): string {
    // 커스텀 업로드 사진 (PRO 유저 - '/'로 시작하지 않는 data URL 등)
    if (avatarUrl && !avatarUrl.startsWith("/")) return avatarUrl;
    // 역할별 기본 이미지
    if (role === "CREATOR" || role === "ADMIN") return "/creator.png";
    return "/user.png";
}

export default function AuthStatus({ myPageColor }: AuthStatusProps) {
    const [session, setSession] = useState<SessionData | null>(null);
    const [loaded, setLoaded] = useState(false);

    const loadSession = useCallback(async () => {
        try {
            const response = await fetch("/api/auth/session", { cache: "no-store" });
            if (!response.ok) return;
            const data = (await response.json()) as SessionResponse;
            setSession(data.session ?? null);
        } finally {
            setLoaded(true);
        }
    }, []);

    useEffect(() => {
        loadSession();
    }, [loadSession]);

    // 프로필 사진 변경 또는 구독 해지 시 즉시 갱신
    useEffect(() => {
        const handler = () => { void loadSession(); };
        window.addEventListener("avatar-updated", handler);
        return () => window.removeEventListener("avatar-updated", handler);
    }, [loadSession]);

    if (!loaded) return null;

    if (!session) {
        return (
            <a
                href="/api/auth/kakao"
                className="text-[13px] font-semibold transition-opacity hover:opacity-70"
                style={{ color: "#3A1D1D" }}
            >
                카카오 로그인
            </a>
        );
    }

    const avatarSrc = getAvatarSrc(session.role, session.avatarUrl);

    return (
        <div className="flex items-center gap-3">
            <Link href="/mypage" className="shrink-0 transition-opacity hover:opacity-80">
                <Image
                    src={avatarSrc}
                    alt={session.nickname ?? "프로필"}
                    width={30}
                    height={30}
                    className="rounded-full object-cover"
                    style={{ width: 30, height: 30 }}
                    unoptimized={!!session.avatarUrl && !session.avatarUrl.startsWith("/")}
                />
            </Link>
            <span className="text-[13px] font-semibold" style={{ color: "#3A1D1D" }}>
                {session.nickname ?? "사용자"}
            </span>
            <Link
                href="/mypage"
                className="text-[13px] font-semibold transition-opacity hover:opacity-70"
                style={{ color: myPageColor ?? "#3A1D1D" }}
            >
                마이페이지
            </Link>
            <a
                href="/api/auth/logout"
                className="px-2 py-1 rounded-md text-[12px] font-semibold transition-opacity hover:opacity-70"
                style={{ border: "1px solid #3A1D1D", color: "#3A1D1D" }}
            >
                로그아웃
            </a>
        </div>
    );
}

"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";

export type BubbleSide = "send" | "receive";

export interface BubbleDesignOptions {
  side: BubbleSide;
  bgColor: string;
  characterUrl?: string;
}

export const DEFAULT_SEND: BubbleDesignOptions = {
  side: "send",
  bgColor: "#FEE500",
  characterUrl: undefined,
};

export const DEFAULT_RECEIVE: BubbleDesignOptions = {
  side: "receive",
  bgColor: "#FFFFFF",
  characterUrl: undefined,
};

// dataURL → objectURL 변환 (동기) — draw 함수보다 반드시 앞에 선언
function dataURLtoObjectURL(dataUrl: string): string {
  const arr  = dataUrl.split(",");
  const mime = arr[0].match(/:(.*?);/)![1];
  const bstr = atob(arr[1]);
  let n = bstr.length;
  const u8arr = new Uint8Array(n);
  while (n--) u8arr[n] = bstr.charCodeAt(n);
  return URL.createObjectURL(new Blob([u8arr], { type: mime }));
}

// ── 좌표 상수
const SEND_BUBBLE  = { cx: 48.10345,  cy: 160.51724, r: 44.48276 };
const SEND_CHAR    = { cx: 125.51724, cy: 68.96552,  r: 62.58621 };
const CANVAS_SIZE  = 210;
const SEND2_W      = 210;
const SEND2_H      = 90;
const SEND2_BUBBLE = { cx: 45.68966, cy: 45.68966,  r: 42.75862 };
const SEND3_W      = 120;
const SEND3_H      = 90;
const SEND3_BUBBLE = { cx: 45.51724, cy: 45.33392,  r: 43.27586 };
const RECEIVE1_W      = 110;
const RECEIVE1_H      = 90;
const RECEIVE1_BUBBLE = { cx: 65.51724, cy: 44.82759, r: 43.27586 };
const RECEIVE2_W      = 110;
const RECEIVE2_H      = 90;
const RECEIVE2_BUBBLE = { cx: 65.51724, cy: 44.82759, r: 43.27586 };

/** bubble-send.svg 기반 PNG 생성 — 동기 */
export function drawBubbleSync(opts: BubbleDesignOptions, charImg: HTMLImageElement | null): string {
  const canvas = document.createElement("canvas");
  canvas.width  = CANVAS_SIZE;
  canvas.height = CANVAS_SIZE;
  const ctx = canvas.getContext("2d")!;
  ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);
  ctx.beginPath();
  ctx.arc(SEND_BUBBLE.cx, SEND_BUBBLE.cy, SEND_BUBBLE.r, 0, Math.PI * 2);
  ctx.fillStyle = opts.bgColor;
  ctx.fill();
  if (charImg) {
    ctx.save();
    ctx.beginPath();
    ctx.arc(SEND_CHAR.cx, SEND_CHAR.cy, SEND_CHAR.r, 0, Math.PI * 2);
    ctx.clip();
    ctx.drawImage(charImg, SEND_CHAR.cx - SEND_CHAR.r, SEND_CHAR.cy - SEND_CHAR.r, SEND_CHAR.r * 2, SEND_CHAR.r * 2);
    ctx.restore();
  }
  return dataURLtoObjectURL(canvas.toDataURL("image/png"));
}

