  const [localBgColor, setLocalBgColor] = useState(options.bgColor);
  useEffect(() => { setLocalBgColor(options.bgColor); }, [options.bgColor]);

  // rAF 스로틀용 ref
  const rafRef      = useRef<number | null>(null);
  const pendingColor = useRef(options.bgColor);

  // 테마 복원 시 characterUrl 복원
  useEffect(() => {
    if (restoredRef.current) return;
    if (options.characterUrl) {
      restoredRef.current = true;
      setCharPreviewUrl(options.characterUrl);
      const img = new Image();
      img.onload = () => setCharImgEl(img);
      img.src = options.characterUrl;
    }
  }, [options.characterUrl]);

  // 동기 생성 — options 확정 시에만
  const autoGenerate = useCallback(
    (opts: BubbleDesignOptions, img: HTMLImageElement | null) => {
      setStatus("generating");
      try {
        if (prevUrlsRef.current) {
          URL.revokeObjectURL(prevUrlsRef.current.bubble1);
          URL.revokeObjectURL(prevUrlsRef.current.bubble2);
        }
        const url1 = opts.side === "send"
          ? (img ? drawBubbleSync(opts, img) : drawBubble3SendSync(opts.bgColor))
          : drawBubble1ReceiveSync(opts.bgColor);
        const url2 = opts.side === "send"
          ? (img ? drawBubble2SendSync(opts.bgColor) : drawBubble3SendSync(opts.bgColor))
          : drawBubble2ReceiveSync(opts.bgColor);
        prevUrlsRef.current = { bubble1: url1, bubble2: url2 };
        onGenerate({ bubble1: url1, bubble2: url2 });
        setStatus("done");
      } catch {
        setStatus("idle");
      }
    },
    [onGenerate]
  );

  useEffect(() => {
    autoGenerate(options, charImgEl);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [options, charImgEl]);

  // rAF 스로틀: 드래그 중 상위 onChange 전파를 1프레임에 1번만
  const scheduleOnChange = useCallback((color: string) => {
    pendingColor.current = color;
    if (rafRef.current !== null) return;
    rafRef.current = requestAnimationFrame(() => {
      rafRef.current = null;
      onChange({ ...options, bgColor: pendingColor.current });
    });
  }, [onChange, options]);

  useEffect(() => () => { if (rafRef.current !== null) cancelAnimationFrame(rafRef.current); }, []);

  const handleCharUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const url = URL.createObjectURL(file);
    setCharPreviewUrl(url);
    const img = new Image();
    img.onload = () => setCharImgEl(img);
    img.src = url;
    onChange({ ...options, characterUrl: url });
  };

  const handleRemoveChar = () => {
    setCharPreviewUrl(null);
    setCharImgEl(null);
    if (charInputRef.current) charInputRef.current.value = "";
    onChange({ ...options, characterUrl: undefined });
  };

  const label = side === "send" ? "보낸 메시지" : "받은 메시지";

  return (
    <div className="flex flex-col gap-3 py-2">
      {/* 상태 표시 */}
      <div className="mx-2.5 flex items-center gap-2 py-1.5 px-3 rounded-lg"
        style={{ backgroundColor: status === "done" ? "rgba(34,197,94,0.08)" : status === "generating" ? "rgba(251,146,60,0.08)" : "rgba(0,0,0,0.03)" }}>
        <span className="text-[10px]">
          {status === "generating" ? "⏳" : status === "done" ? "✅" : "⬜"}
        </span>
        <span className="text-[11px] font-medium"
          style={{ color: status === "done" ? "rgb(22,163,74)" : status === "generating" ? "rgb(251,146,60)" : "#9ca3af" }}>
          {status === "generating" ? "목업에 반영 중..." : status === "done" ? `${label} 말풍선 목업에 반영됨` : "설정을 변경하면 목업에 자동 반영됩니다"}
        </span>
      </div>

      {/* 말풍선 색상 */}
      <ColorPaletteRow
        label="말풍선 색상"
        value={localBgColor}
        onChange={(v) => {
          setLocalBgColor(v);
          scheduleOnChange(v);
        }}
        isPro={isPro}
      />

      {/* 캐릭터 이미지 (send만 표시) */}
      {side === "send" && (
        <div className="px-2.5 py-1">
          <div className="flex items-center justify-between mb-1.5">
            <div className="flex flex-col">
              <span className="text-[12px] font-medium text-gray-500">캐릭터 이미지</span>
              <span className="text-[10px] text-gray-400">선택사항입니다</span>
            </div>
            {charPreviewUrl ? (
              <button type="button" onClick={handleRemoveChar}
                className="text-[10px] text-red-500 px-2 py-0.5 bg-red-50 rounded-md">
                삭제
              </button>
            ) : (
              <label className="cursor-pointer flex items-center gap-1 text-[10px] text-orange-500 px-2 py-0.5 bg-orange-50 rounded-md">
                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/>
                  <polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/>
                </svg>
                업로드
                <input ref={charInputRef} type="file" accept="image/*" className="hidden" onChange={handleCharUpload} />
              </label>
            )}
          </div>
          {charPreviewUrl && (
            // eslint-disable-next-line @next/next/no-img-element
            <img src={charPreviewUrl} alt="캐릭터" className="w-12 h-12 object-contain rounded-lg border border-gray-100" />
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { memo, useState, useEffect, useRef } from "react";
import React from "react";

/* ── Pro 전용 프리셋 팔레트 색상 (21색, 7열 × 3행) ── */
export const PALETTE_PRESETS: { hex: string; name: string }[] = [
  { hex: "#FFFFFF", name: "흰색" },
  { hex: "#F5F5F5", name: "밝은 회색" },
  { hex: "#9E9E9E", name: "중간 회색" },
  { hex: "#424242", name: "어두운 회색" },
  { hex: "#212121", name: "부드러운 검정" },
  { hex: "#007BFF", name: "트러스트 블루" },
  { hex: "#28A745", name: "활기찬 그린" },
  { hex: "#FFC107", name: "옐로우 골드" },
  { hex: "#DC3545", name: "데인저 레드" },
  { hex: "#6F42C1", name: "딥 퍼플" },
  { hex: "#FD7E14", name: "에너제틱 오렌지" },
  { hex: "#0D6EFD", name: "로열 블루" },
  { hex: "#052C65", name: "미드나잇 네이비" },
  { hex: "#795548", name: "초콜릿 브라운" },
  { hex: "#FFD9EB", name: "파스텔 핑크" },
  { hex: "#FFF3CD", name: "크림 옐로우" },
  { hex: "#D1E7DD", name: "에어리 민트" },
  { hex: "#CFE2FF", name: "소프트 스카이" },
  { hex: "#E2D9F3", name: "라벤더 미스트" },
  { hex: "#FFE5D9", name: "피치 푸딩" },
  { hex: "#F8F9FA", name: "샌드 베이지" },
];

export interface ColorPaletteRowProps {
  label: string;
  value: string;
  onChange: (v: string) => void;
  tooltip?: string;
  disabled?: boolean;
  isPro: boolean;
}

export const ColorPaletteRow = memo(function ColorPaletteRow({
  label, value, onChange, tooltip, disabled = false, isPro,
}: ColorPaletteRowProps) {
  const [paletteOpen, setPaletteOpen] = useState(false);
  const [hexInput, setHexInput] = useState((value ?? "#FFFFFF").toUpperCase());
  const [popupStyle, setPopupStyle] = useState<React.CSSProperties>({});
  const btnRef = useRef<HTMLButtonElement>(null);
  const popupRef = useRef<HTMLDivElement>(null);
  const rafRef = useRef<number | null>(null);
  const pendingColorRef = useRef(value ?? "#FFFFFF");

  // 외부 클릭 시 팝업 닫기
  useEffect(() => {
    if (!paletteOpen) return;
    const handleOutside = (e: MouseEvent) => {
      if (
        !(btnRef.current?.contains(e.target as Node)) &&
        !(popupRef.current?.contains(e.target as Node))
      ) {
        setPaletteOpen(false);
      }
    };
    document.addEventListener("mousedown", handleOutside);
    return () => document.removeEventListener("mousedown", handleOutside);
  }, [paletteOpen]);

  useEffect(() => {
    return () => { if (rafRef.current !== null) cancelAnimationFrame(rafRef.current); };
  }, []);

  // 팔레트 열기 – 이벤트 핸들러에서 hexInput 초기화
  const handleOpenPalette = () => {
    if (disabled) return;
    if (!paletteOpen) {
      setHexInput((value ?? "#FFFFFF").toUpperCase());
      pendingColorRef.current = value ?? "#FFFFFF";

      // position:fixed 좌표 계산 → 사이드바 overflow:hidden 무시
      if (btnRef.current) {
        const rect = btnRef.current.getBoundingClientRect();
        const POPUP_H = 360;
        const rightEdge = window.innerWidth - rect.right;
        const safeRight = Math.max(8, rightEdge - 4);
        const spaceBelow = window.innerHeight - rect.bottom - 8;

        if (spaceBelow >= POPUP_H) {
          setPopupStyle({ top: rect.bottom + 8, right: safeRight });
        } else {
          setPopupStyle({ bottom: window.innerHeight - rect.top + 8, right: safeRight });
        }
      }
    }
    setPaletteOpen((prev) => !prev);
  };

  const scheduleLiveUpdate = (color: string) => {
    pendingColorRef.current = color;
    if (rafRef.current !== null) return;
    rafRef.current = requestAnimationFrame(() => {
      rafRef.current = null;
      onChange(pendingColorRef.current);
    });
  };

  const applyHex = () => {
    const raw = hexInput.trim();
    const v = raw.startsWith("#") ? raw : `#${raw}`;
    if (/^#[0-9A-Fa-f]{6}$/.test(v)) {
      onChange(v.toUpperCase());
      setPaletteOpen(false);
    }
  };

  const handlePresetClick = (hex: string) => {
    if (!isPro) return;
    onChange(hex);
    setHexInput(hex);
  };

  return (
    <div
      data-setting-item="true"
      className="flex items-center justify-between gap-3 py-1.5 px-2.5 group transition-all duration-200 hover:bg-gray-50 rounded-lg w-full"
      style={{ opacity: disabled ? 0.5 : 1 }}
    >
      {/* 라벨 */}
      <div className="flex flex-col gap-0.5 flex-1 min-w-0">
        <div className="flex items-center gap-1.5">
          <span className="text-[12px] font-medium text-gray-500">{label}</span>
          {tooltip && (
            <div className="group/tip relative flex items-center">
              <svg
                width="11" height="11" viewBox="0 0 24 24"
                fill="none" stroke="currentColor" strokeWidth="2"
                strokeLinecap="round" strokeLinejoin="round"
                className="text-gray-300"
              >
                <circle cx="12" cy="12" r="10" />
                <path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3" />
                <line x1="12" y1="17" x2="12.01" y2="17" />
              </svg>
              <div className="absolute left-0 bottom-6 z-50 hidden group-hover/tip:block text-[11px] rounded-lg px-3 py-2 w-max max-w-[200px] leading-snug shadow-xl ring-1 ring-black/5 bg-white text-gray-800">
                {tooltip}
                <div className="absolute left-1.5 -bottom-1 w-2 h-2 bg-white rotate-45 transform border-b border-r border-gray-100" />
              </div>
            </div>
          )}
        </div>
      </div>

      {/* 색상 버튼 + hex 값 */}
      <div className="flex items-center gap-2 shrink-0">
        <button
          ref={btnRef}
          type="button"
          disabled={disabled}
          onClick={handleOpenPalette}
          className="group/picker focus:outline-none"
        >
          <div
            className="w-5 h-5 rounded-full shadow-sm transition-all duration-200 group-hover/picker:scale-110 ring-1 ring-black/5"
            style={{ backgroundColor: value }}
          />
        </button>
        <div className="text-[11px] font-mono text-gray-400 w-[56px] text-right uppercase tracking-wide">
          {value}
        </div>
      </div>

      {/* 팔레트 팝업 – position:fixed 로 overflow 클리핑 완전 탈출 */}
      {paletteOpen && !disabled && (
        <div
          ref={popupRef}
          style={{ position: "fixed", zIndex: 9999, width: 236, ...popupStyle }}
          className="bg-white rounded-2xl shadow-2xl border border-gray-100 p-3"
        >
          {/* 헤더 */}
          <div className="flex items-center justify-between mb-2.5">
            <span className="text-[12px] font-bold text-gray-700">색상 선택</span>
            <button
              type="button"
              onClick={() => setPaletteOpen(false)}
              className="text-gray-300 hover:text-gray-500 transition-colors"
            >
              <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                <line x1="18" y1="6" x2="6" y2="18" />
                <line x1="6" y1="6" x2="18" y2="18" />
              </svg>
            </button>
          </div>

          {/* 프리셋 팔레트 – Pro 전용, 7열 × 3행 */}
          <div className="mb-2.5">
            <div className="flex items-center gap-1.5 mb-2">
              <span className="text-[10px] font-semibold text-gray-500">프리셋 팔레트</span>
              <span
                className="text-[8px] font-bold text-white px-1.5 py-0.5 rounded-full"
                style={{ background: "linear-gradient(90deg,#f97316,#f59e0b)" }}
              >
                PRO
              </span>
            </div>
            <div className="relative">
              <div className={`grid grid-cols-7 gap-1.5 ${!isPro ? "pointer-events-none" : ""}`}>
                {PALETTE_PRESETS.map(({ hex, name }) => (
                  <button
                    key={hex}
                    type="button"
                    onClick={() => handlePresetClick(hex)}
                    title={`${name}\n${hex}`}
                    className="w-[24px] h-[24px] rounded-full transition-all duration-150 hover:scale-110 hover:ring-2 hover:ring-orange-400 hover:ring-offset-1 focus:outline-none"
                    style={{
                      backgroundColor: hex,
                      boxShadow: value.toUpperCase() === hex
                        ? "0 0 0 2px #f97316"
                        : "0 0 0 1px rgba(0,0,0,0.12)",
                    }}
                  />
                ))}
              </div>
              {/* 비 Pro 잠금 오버레이 */}
              {!isPro && (
                <div className="absolute inset-0 bg-white/85 backdrop-blur-[1px] rounded-xl flex flex-col items-center justify-center gap-1.5">
                  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#d1d5db" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
                    <path d="M7 11V7a5 5 0 0 1 10 0v4" />
                  </svg>
                  <span className="text-[10px] font-semibold text-gray-400">Pro 전용 기능</span>
                  <a
                    href="/pricing"
                    className="text-[9px] text-orange-400 font-semibold hover:underline"
                    onClick={() => setPaletteOpen(false)}
                  >
                    업그레이드 →
                  </a>
                </div>
              )}
            </div>
          </div>

          <hr className="border-gray-100 mb-2.5" />

          {/* 직접 입력 – 모든 사용자 */}
          <div>
            <span className="text-[10px] font-semibold text-gray-500 mb-2 block">직접 입력</span>
            <div className="flex items-center gap-2">
              {/* 네이티브 컬러 피커 */}
              <label className="relative cursor-pointer shrink-0">
                <input
                  type="color"
                  value={/^#[0-9A-Fa-f]{6}$/.test(hexInput) ? hexInput : "#000000"}
                  onChange={(e) => {
                    const v = e.target.value.toUpperCase();
                    setHexInput(v);
                    scheduleLiveUpdate(v);
                  }}
                  className="opacity-0 absolute inset-0 w-full h-full cursor-pointer z-10"
                />
                <div
                  className="w-[26px] h-[26px] rounded-full ring-1 ring-black/10 shadow-sm transition-transform hover:scale-110"
                  style={{ backgroundColor: /^#[0-9A-Fa-f]{6}$/.test(hexInput) ? hexInput : "#000000" }}
                />
              </label>
              {/* Hex 입력 */}
              <input
                type="text"
                value={hexInput}
                onChange={(e) => setHexInput(e.target.value.toUpperCase())}
                onKeyDown={(e) => { if (e.key === "Enter") applyHex(); }}
                placeholder="#FFFFFF"
                maxLength={7}
                className="flex-1 text-[11px] font-mono border border-gray-200 rounded-lg px-2 py-1.5 outline-none focus:border-orange-400 focus:ring-1 focus:ring-orange-400/30 transition-all"
              />
            </div>
            <button
              type="button"
              onClick={applyHex}
              className="mt-2 w-full text-[11px] font-semibold text-white rounded-lg py-1.5 transition-opacity hover:opacity-90"
              style={{ background: "linear-gradient(90deg,#f97316,#f59e0b)" }}
            >
              적용
            </button>
          </div>
        </div>
      )}
    </div>
  );
});

"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";

// theme-icon.svg 크기
const ICON_W = 162;
const ICON_H = 162;

// SVG path 데이터 (theme-icon.svg에서 추출)
const BUBBLE_BODY = "M83.30357,26.2723C50.62004,26.2723 29.82142,48.17498 29.82142,75.40535C29.82142,102.63571 50.62004,120.98661 83.30357,120.98661C98.15972,120.98661 111.82738,116.25089 121.92957,107.9634C130.84326,100.26787 136.78572,88.42857 136.78572,75.40535C136.78572,48.17498 115.9871,26.2723 83.30357,26.2723Z";
const BUBBLE_TAIL = "M82.05448,111.11523L48.18209,138.09307L58.13492,95.94946L82.05448,111.11523Z";

function drawIconOnCanvas(
  ctx: CanvasRenderingContext2D,
  bgColor: string,
  iconColor: string
) {
  ctx.clearRect(0, 0, ICON_W, ICON_H);

  // 1. 배경색
  ctx.fillStyle = bgColor;
  ctx.fillRect(0, 0, ICON_W, ICON_H);

  // 2. 말풍선 본체
  ctx.fillStyle = iconColor;
  ctx.fill(new Path2D(BUBBLE_BODY));

  // 3. 말풍선 꼬리
  ctx.fill(new Path2D(BUBBLE_TAIL));
}

// dataURL → objectURL 변환 (동기)
function dataURLtoObjectURL(dataUrl: string): string {
  const arr = dataUrl.split(",");
  const mime = arr[0].match(/:(.*?);/)![1];
  const bstr = atob(arr[1]);
  let n = bstr.length;
  const u8arr = new Uint8Array(n);
  while (n--) u8arr[n] = bstr.charCodeAt(n);
  return URL.createObjectURL(new Blob([u8arr], { type: mime }));
}

/** 아이콘 PNG 동기 생성 → objectURL 반환 */
export function drawIconSync(bgColor: string, iconColor: string): string {
  const canvas = document.createElement("canvas");
  canvas.width = ICON_W;
  canvas.height = ICON_H;
  const ctx = canvas.getContext("2d")!;
  drawIconOnCanvas(ctx, bgColor, iconColor);
  return dataURLtoObjectURL(canvas.toDataURL("image/png"));
}

export interface IconDesignOptions {
  bgColor: string;
  iconColor: string;
}

interface IconDesignerProps {
  options: IconDesignOptions;
  onChange: (opts: IconDesignOptions) => void;
  /** SVG 모드에서 생성된 PNG URL */
  onSvgGenerate: (url: string) => void;
  /** 현재 모드 변경 콜백 */
  onModeChange: (mode: "svg" | "image") => void;
  /** 이미지 업로드 탭에서 업로드된 URL */
  uploadedUrl?: string;
  onUpload: (file: File) => void;
  onRemoveUpload: () => void;
}

export function IconDesigner({
  options,
  onChange,
  onSvgGenerate,
  onModeChange,
  uploadedUrl,
  onUpload,
  onRemoveUpload,
}: IconDesignerProps) {
  const [mode, setMode] = useState<"svg" | "image">("svg");
  const [status, setStatus] = useState<"idle" | "generating" | "done">("idle");
  const previewCanvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const prevUrlRef = useRef<string | null>(null);

  // 로컬 색상 (미리보기 원형 즉시 반영용)
  const [localBgColor, setLocalBgColor]     = useState(options.bgColor);
  const [localIconColor, setLocalIconColor] = useState(options.iconColor);

  // 외부 변경 동기화
  useEffect(() => { setLocalBgColor(options.bgColor); },   [options.bgColor]);
  useEffect(() => { setLocalIconColor(options.iconColor); }, [options.iconColor]);

  // rAF 스로틀용 ref
  const rafRef       = useRef<number | null>(null);
  const pendingBg    = useRef(options.bgColor);
  const pendingIcon  = useRef(options.iconColor);

  // 미리보기 캔버스 — 로컬 색상으로 즉시 렌더
  useEffect(() => {
    if (mode !== "svg") return;
    const canvas = previewCanvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    drawIconOnCanvas(ctx, localBgColor, localIconColor);
  }, [localBgColor, localIconColor, mode]);

  // objectURL 생성 + 상위 전파
  const autoGenerate = useCallback(
    (opts: IconDesignOptions) => {
      setStatus("generating");
      try {
        if (prevUrlRef.current) URL.revokeObjectURL(prevUrlRef.current);
        const url = drawIconSync(opts.bgColor, opts.iconColor);
        prevUrlRef.current = url;
        onSvgGenerate(url);
        setStatus("done");
      } catch {
        setStatus("idle");
      }
    },
    [onSvgGenerate]
  );

  // options 확정 시 objectURL 생성
  useEffect(() => {
    if (mode !== "svg") return;
    autoGenerate(options);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [options, mode]);

  // rAF 스로틀: 드래그 중 상위 onChange 전파를 1프레임에 1번만
  const scheduleOnChange = useCallback((bg: string, icon: string) => {
    pendingBg.current   = bg;
    pendingIcon.current = icon;
    if (rafRef.current !== null) return;
    rafRef.current = requestAnimationFrame(() => {
      rafRef.current = null;
      onChange({ bgColor: pendingBg.current, iconColor: pendingIcon.current });
    });
  }, [onChange]);

  useEffect(() => () => { if (rafRef.current !== null) cancelAnimationFrame(rafRef.current); }, []);

  const handleModeSwitch = (next: "svg" | "image") => { setMode(next); onModeChange(next); };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setMode("image"); onModeChange("image"); onUpload(file); e.target.value = "";
  };

  return (
    <div className="flex flex-col gap-3 py-2">
      {/* 모드 탭 */}
      <div className="mx-2.5 flex rounded-lg overflow-hidden border border-gray-200">
        <button type="button" onClick={() => handleModeSwitch("svg")}
          className="flex-1 py-1.5 text-[11px] font-semibold transition-colors"
          style={{ backgroundColor: mode === "svg" ? "rgb(251,146,60)" : "#fff", color: mode === "svg" ? "#fff" : "#9ca3af" }}>
          색상으로 제작
        </button>
        <button type="button" onClick={() => handleModeSwitch("image")}
          className="flex-1 py-1.5 text-[11px] font-semibold transition-colors"
          style={{ backgroundColor: mode === "image" ? "rgb(251,146,60)" : "#fff", color: mode === "image" ? "#fff" : "#9ca3af" }}>
          이미지 업로드
        </button>
      </div>

      {mode === "svg" && (
        <>
          <div className="mx-2.5 flex items-center gap-2 py-1.5 px-3 rounded-lg"
            style={{ backgroundColor: status === "done" ? "rgba(34,197,94,0.08)" : "rgba(0,0,0,0.03)" }}>
            <span className="text-[10px]">{status === "done" ? "✅" : "⬜"}</span>
            <span className="text-[11px] font-medium" style={{ color: status === "done" ? "rgb(22,163,74)" : "#9ca3af" }}>
              {status === "done" ? "아이콘 적용됨" : "색상을 변경하면 자동 반영됩니다"}
            </span>
          </div>

          {/* 배경 색상 */}
          <div className="flex items-center justify-between px-2.5 py-1">
            <span className="text-[12px] font-medium text-gray-500">배경 색상</span>
            <div className="flex items-center gap-2">
              <label className="relative cursor-pointer">
                <input
                  type="color"
                  value={localBgColor}
                  onChange={(e) => {
                    const v = e.target.value;
                    setLocalBgColor(v);
                    scheduleOnChange(v, pendingIcon.current);
                  }}
                  className="opacity-0 absolute inset-0 w-full h-full cursor-pointer z-10"
                />
                <div className="w-5 h-5 rounded-full ring-1 ring-black/10 shadow-sm" style={{ backgroundColor: localBgColor }} />
              </label>
              <span className="text-[11px] font-mono text-gray-400 w-[56px] uppercase">{localBgColor}</span>
            </div>
          </div>

          {/* 아이콘 색상 */}
          <div className="flex items-center justify-between px-2.5 py-1">
            <span className="text-[12px] font-medium text-gray-500">아이콘 색상</span>
            <div className="flex items-center gap-2">
              <label className="relative cursor-pointer">
                <input
                  type="color"
                  value={localIconColor}
                  onChange={(e) => {
                    const v = e.target.value;
                    setLocalIconColor(v);
                    scheduleOnChange(pendingBg.current, v);
                  }}
                  className="opacity-0 absolute inset-0 w-full h-full cursor-pointer z-10"
                />
                <div className="w-5 h-5 rounded-full ring-1 ring-black/10 shadow-sm" style={{ backgroundColor: localIconColor }} />
              </label>
              <span className="text-[11px] font-mono text-gray-400 w-[56px] uppercase">{localIconColor}</span>
            </div>
          </div>

          {/* 미리보기 */}
          <div className="px-2.5 pb-1">
            <span className="text-[11px] font-medium text-gray-400 block mb-1.5">미리보기</span>
            <canvas ref={previewCanvasRef} width={ICON_W} height={ICON_H}
              className="w-16 h-16 rounded-xl border border-gray-100 shadow-sm" />
          </div>
        </>
      )}

      {mode === "image" && (
        <div className="px-2.5 py-1">
          <div className="flex items-center justify-between mb-2">
            <span className="text-[12px] font-medium text-gray-500">아이콘 이미지</span>
            {uploadedUrl ? (
              <button type="button" onClick={onRemoveUpload}
                className="text-[10px] text-red-500 px-2 py-0.5 bg-red-50 rounded-md">삭제</button>
            ) : (
              <label className="cursor-pointer flex items-center gap-1 text-[10px] text-orange-500 px-2 py-0.5 bg-orange-50 rounded-md">
                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/>
                  <polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/>
                </svg>
                업로드
                <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
              </label>
            )}
          </div>
          {uploadedUrl && (
            // eslint-disable-next-line @next/next/no-img-element
            <img src={uploadedUrl} alt="아이콘" className="w-16 h-16 object-contain rounded-xl border border-gray-100 shadow-sm" />
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";
import { ColorPaletteRow } from "./ColorPaletteRow";

// theme-icon.svg 크기
const ICON_W = 162;
const ICON_H = 162;

// SVG path 데이터 (theme-icon.svg에서 추출)
const BUBBLE_BODY = "M83.30357,26.2723C50.62004,26.2723 29.82142,48.17498 29.82142,75.40535C29.82142,102.63571 50.62004,120.98661 83.30357,120.98661C98.15972,120.98661 111.82738,116.25089 121.92957,107.9634C130.84326,100.26787 136.78572,88.42857 136.78572,75.40535C136.78572,48.17498 115.9871,26.2723 83.30357,26.2723Z";
const BUBBLE_TAIL = "M82.05448,111.11523L48.18209,138.09307L58.13492,95.94946L82.05448,111.11523Z";

function drawIconOnCanvas(
  ctx: CanvasRenderingContext2D,
  bgColor: string,
  iconColor: string
) {
  ctx.clearRect(0, 0, ICON_W, ICON_H);

  // 1. 배경색
  ctx.fillStyle = bgColor;
  ctx.fillRect(0, 0, ICON_W, ICON_H);

  // 2. 말풍선 본체
  ctx.fillStyle = iconColor;
  ctx.fill(new Path2D(BUBBLE_BODY));

  // 3. 말풍선 꼬리
  ctx.fill(new Path2D(BUBBLE_TAIL));
}

// dataURL → objectURL 변환 (동기)
function dataURLtoObjectURL(dataUrl: string): string {
  const arr = dataUrl.split(",");
  const mime = arr[0].match(/:(.*?);/)![1];
  const bstr = atob(arr[1]);
  let n = bstr.length;
  const u8arr = new Uint8Array(n);
  while (n--) u8arr[n] = bstr.charCodeAt(n);
  return URL.createObjectURL(new Blob([u8arr], { type: mime }));
}

/** 아이콘 PNG 동기 생성 → objectURL 반환 */
export function drawIconSync(bgColor: string, iconColor: string): string {
  const canvas = document.createElement("canvas");
  canvas.width = ICON_W;
  canvas.height = ICON_H;
  const ctx = canvas.getContext("2d")!;
  drawIconOnCanvas(ctx, bgColor, iconColor);
  return dataURLtoObjectURL(canvas.toDataURL("image/png"));
}

export interface IconDesignOptions {
  bgColor: string;
  iconColor: string;
}

interface IconDesignerProps {
  options: IconDesignOptions;
  onChange: (opts: IconDesignOptions) => void;
  onSvgGenerate: (url: string) => void;
  onModeChange: (mode: "svg" | "image") => void;
  /** 이미지 업로드 탭에서 업로드된 URL */
  uploadedUrl?: string;
  onUpload: (file: File) => void;
  onRemoveUpload: () => void;
  isPro: boolean;
}

export function IconDesigner({
  options,
  onChange,
  onSvgGenerate,
  onModeChange,
  uploadedUrl,
  onUpload,
  onRemoveUpload,
  isPro,
}: IconDesignerProps) {
  const [mode, setMode] = useState<"svg" | "image">("svg");
  const [status, setStatus] = useState<"idle" | "generating" | "done">("idle");
  const previewCanvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const prevUrlRef = useRef<string | null>(null);

  // 로컬 색상 (미리보기 원형 즉시 반영용)
  const [localBgColor, setLocalBgColor]     = useState(options.bgColor);
  const [localIconColor, setLocalIconColor] = useState(options.iconColor);

  // 외부 변경 동기화
  useEffect(() => { setLocalBgColor(options.bgColor); },   [options.bgColor]);
  useEffect(() => { setLocalIconColor(options.iconColor); }, [options.iconColor]);

  // rAF 스로틀용 ref
  const rafRef       = useRef<number | null>(null);
  const pendingBg    = useRef(options.bgColor);
  const pendingIcon  = useRef(options.iconColor);

  // 미리보기 캔버스 — 로컬 색상으로 즉시 렌더
  useEffect(() => {
    if (mode !== "svg") return;
    const canvas = previewCanvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    drawIconOnCanvas(ctx, localBgColor, localIconColor);
  }, [localBgColor, localIconColor, mode]);

  // objectURL 생성 + 상위 전파
  const autoGenerate = useCallback(
    (opts: IconDesignOptions) => {
      setStatus("generating");
      try {
        if (prevUrlRef.current) URL.revokeObjectURL(prevUrlRef.current);
        const url = drawIconSync(opts.bgColor, opts.iconColor);
        prevUrlRef.current = url;
        onSvgGenerate(url);
        setStatus("done");
      } catch {
        setStatus("idle");
      }
    },
    [onSvgGenerate]
  );

  // options 확정 시 objectURL 생성
  useEffect(() => {
    if (mode !== "svg") return;
    autoGenerate(options);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [options, mode]);

  // rAF 스로틀: 드래그 중 상위 onChange 전파를 1프레임에 1번만
  const scheduleOnChange = useCallback((bg: string, icon: string) => {
    pendingBg.current   = bg;
    pendingIcon.current = icon;
    if (rafRef.current !== null) return;
    rafRef.current = requestAnimationFrame(() => {
      rafRef.current = null;
      onChange({ bgColor: pendingBg.current, iconColor: pendingIcon.current });
    });
  }, [onChange]);

  useEffect(() => () => { if (rafRef.current !== null) cancelAnimationFrame(rafRef.current); }, []);

  const handleModeSwitch = (next: "svg" | "image") => { setMode(next); onModeChange(next); };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setMode("image"); onModeChange("image"); onUpload(file); e.target.value = "";
  };

  return (
    <div className="flex flex-col gap-3 py-2">
      {/* 모드 탭 */}
      <div className="mx-2.5 flex rounded-lg overflow-hidden border border-gray-200">
        <button type="button" onClick={() => handleModeSwitch("svg")}
          className="flex-1 py-1.5 text-[11px] font-semibold transition-colors"
          style={{ backgroundColor: mode === "svg" ? "rgb(251,146,60)" : "#fff", color: mode === "svg" ? "#fff" : "#9ca3af" }}>
          색상으로 제작
        </button>
        <button type="button" onClick={() => handleModeSwitch("image")}
          className="flex-1 py-1.5 text-[11px] font-semibold transition-colors"
          style={{ backgroundColor: mode === "image" ? "rgb(251,146,60)" : "#fff", color: mode === "image" ? "#fff" : "#9ca3af" }}>
          이미지 업로드
        </button>
      </div>

      {mode === "svg" && (
        <>
          <div className="mx-2.5 flex items-center gap-2 py-1.5 px-3 rounded-lg"
            style={{ backgroundColor: status === "done" ? "rgba(34,197,94,0.08)" : "rgba(0,0,0,0.03)" }}>
            <span className="text-[10px]">{status === "done" ? "✅" : "⬜"}</span>
            <span className="text-[11px] font-medium" style={{ color: status === "done" ? "rgb(22,163,74)" : "#9ca3af" }}>
              {status === "done" ? "아이콘 적용됨" : "색상을 변경하면 자동 반영됩니다"}
            </span>
          </div>

          {/* 배경 색상 */}
          <ColorPaletteRow
            label="배경 색상"
            value={localBgColor}
            onChange={(v) => {
              setLocalBgColor(v);
              scheduleOnChange(v, pendingIcon.current);
            }}
            isPro={isPro}
          />

          {/* 아이콘 색상 */}
          <ColorPaletteRow
            label="아이콘 색상"
            value={localIconColor}
            onChange={(v) => {
              setLocalIconColor(v);
              scheduleOnChange(pendingBg.current, v);
            }}
            isPro={isPro}
          />

          {/* 미리보기 */}
          <div className="px-2.5 pb-1">
            <span className="text-[11px] font-medium text-gray-400 block mb-1.5">미리보기</span>
            <canvas ref={previewCanvasRef} width={ICON_W} height={ICON_H}
              className="w-16 h-16 rounded-xl border border-gray-100 shadow-sm" />
          </div>
        </>
      )}

      {mode === "image" && (
        <div className="px-2.5 py-1">
          <div className="flex items-center justify-between mb-2">
            <span className="text-[12px] font-medium text-gray-500">아이콘 이미지</span>
            {uploadedUrl ? (
              <button type="button" onClick={onRemoveUpload}
                className="text-[10px] text-red-500 px-2 py-0.5 bg-red-50 rounded-md">삭제</button>
            ) : (
              <label className="cursor-pointer flex items-center gap-1 text-[10px] text-orange-500 px-2 py-0.5 bg-orange-50 rounded-md">
                <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/>
                  <polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/>
                </svg>
                업로드
                <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
              </label>
            )}
          </div>
          {uploadedUrl && (
            // eslint-disable-next-line @next/next/no-img-element
            <img src={uploadedUrl} alt="아이콘" className="w-16 h-16 object-contain rounded-xl border border-gray-100 shadow-sm" />
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Image from "next/image";
import LoginRequiredModal from "../../components/LoginRequiredModal";

type Theme = {
    id: string;
    title: string;
    price: number;
    thumbnailUrl: string | null;
    tags: string[];
    salesCount: number;
    createdAt: string;
};

type Creator = {
    id: string;
    nickname: string | null;
    name: string;
    avatarUrl: string | null;
    image: string | null;
    role: string;
    createdAt: string;
};

const PLACEHOLDER_GRADIENTS = [
    "linear-gradient(135deg,#e0c3fc,#9d4edd)",
    "linear-gradient(135deg,#90e0ef,#0077b6)",
    "linear-gradient(135deg,#ffcb77,#f83600)",
    "linear-gradient(135deg,#b7e4c7,#1b4332)",
    "linear-gradient(135deg,#ffd6e7,#ff8fab)",
];

export default function CreatorProfileClient({ creatorId }: { creatorId: string }) {
    const router = useRouter();
    const [creator, setCreator] = useState<Creator | null>(null);
    const [themes, setThemes] = useState<Theme[]>([]);
    const [followerCount, setFollowerCount] = useState(0);
    const [isFollowing, setIsFollowing] = useState(false);
    const [loading, setLoading] = useState(true);
    const [followLoading, setFollowLoading] = useState(false);
    const [error, setError] = useState("");
    const [loginModal, setLoginModal] = useState(false);

    useEffect(() => {
        fetch(`/api/creator/${creatorId}`)
            .then(r => r.json())
            .then((data: { creator?: Creator; themes?: Theme[]; followerCount?: number; isFollowing?: boolean; error?: string }) => {
                if (data.error) {
                    setError(data.error);
                    return;
                }
                setCreator(data.creator ?? null);
                setThemes(data.themes ?? []);
                setFollowerCount(data.followerCount ?? 0);
                setIsFollowing(data.isFollowing ?? false);
            })
            .catch(() => setError("크리에이터 정보를 불러올 수 없습니다."))
            .finally(() => setLoading(false));
    }, [creatorId]);

    const handleFollow = async () => {
        setFollowLoading(true);
        try {
            const res = await fetch("/api/follow", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ creatorId }),
            });
            if (res.status === 401) {
                setLoginModal(true);
                return;
            }
            const data = await res.json() as { isFollowing?: boolean; error?: string };
            if (data.isFollowing !== undefined) {
                setIsFollowing(data.isFollowing);
                setFollowerCount(prev => data.isFollowing ? prev + 1 : Math.max(0, prev - 1));
            }
        } catch { /* ignore */ } finally {
            setFollowLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <span className="text-[14px]" style={{ color: "#8e8e93" }}>불러오는 중...</span>
            </div>
        );
    }

    if (error || !creator) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center gap-3">
                <p className="text-[16px]" style={{ color: "#1c1c1e" }}>크리에이터를 찾을 수 없습니다.</p>
                <button onClick={() => router.back()} className="text-[13px]" style={{ color: "#8e8e93" }}>← 뒤로 가기</button>
            </div>
        );
    }

    const displayName = creator.nickname ?? creator.name;
    const avatarSrc = creator.avatarUrl ?? creator.image;

    return (
        <div className="min-h-screen" style={{ background: "#f3f3f3" }}>
            <div style={{ maxWidth: 900, margin: "0 auto", padding: "48px 24px" }}>
                {/* 뒤로 가기 */}
                <button
                    onClick={() => router.back()}
                    className="flex items-center gap-1.5 mb-8 text-[13px] font-medium transition-opacity hover:opacity-60"
                    style={{ color: "#8e8e93" }}
                >
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#8e8e93" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M19 12H5M12 5l-7 7 7 7" />
                    </svg>
                    뒤로 가기
                </button>

                {/* 프로필 카드 */}
                <div
                    className="rounded-[24px] p-8 mb-8"
                    style={{
                        background: "rgba(255,255,255,0.7)",
                        backdropFilter: "blur(20px)",
                        border: "1px solid rgba(255,255,255,0.9)",
                        boxShadow: "0 4px 24px rgba(0,0,0,0.06)",
                    }}
                >
                    <div className="flex items-start gap-6">
                        {/* 아바타 */}
                        <div
                            className="relative shrink-0 rounded-full overflow-hidden"
                            style={{ width: 80, height: 80, background: "#e7e5e4" }}
                        >
                            <Image src={avatarSrc} alt={displayName} fill className="object-cover" />
                            style={{ width: 80, height: 80, background: "linear-gradient(135deg, #FF9500, #FF6B00)" }}

                            {avatarSrc ? (
                                <Image src={avatarSrc} alt={displayName} fill className="object-cover" />
                            ) : (
                                <div className="w-full h-full flex items-center justify-center">
                                    <span className="text-[28px] font-bold text-white">{displayName[0]}</span>
                                </div>
                                {creator.role === "CREATOR" && (
                                    <span className="text-[11px] font-bold px-2 py-0.5 rounded-full" style={{ background: "rgba(255,149,0,0.12)", color: "#FF9500" }}>크리에이터</span>
                                )}
                                {creator.role === "ADMIN" && (
                                    <span className="text-[11px] font-bold px-2 py-0.5 rounded-full" style={{ background: "#FF3B30", color: "#fff" }}>관리자</span>
                                )}
                            </div>

                            <div className="flex items-center gap-6 mt-3">
                                <div className="flex flex-col">
                                    <span className="text-[20px] font-bold" style={{ color: "#1c1c1e" }}>{themes.length}</span>
                                    <span className="text-[12px]" style={{ color: "#8e8e93" }}>테마</span>
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-[20px] font-bold" style={{ color: "#1c1c1e" }}>{followerCount.toLocaleString()}</span>
                                    <span className="text-[12px]" style={{ color: "#8e8e93" }}>팔로워</span>
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-[20px] font-bold" style={{ color: "#1c1c1e" }}>
                                        {themes.reduce((s, t) => s + t.salesCount, 0).toLocaleString()}
                                    </span>
                                    <span className="text-[12px]" style={{ color: "#8e8e93" }}>총 판매</span>
                                </div>
                            </div>
                        </div>

                        {/* 팔로우 버튼 */}
                        <button
                            onClick={handleFollow}
                            disabled={followLoading}
                            className="px-5 py-2 rounded-full text-[13px] font-semibold transition-all active:scale-95 shrink-0"
                            style={{
                                background: isFollowing ? "rgba(0,0,0,0.06)" : "#1c1c1e",
                                color: isFollowing ? "#3a3a3c" : "#fff",
                                border: isFollowing ? "1.5px solid rgba(0,0,0,0.12)" : "none",
                                opacity: followLoading ? 0.6 : 1,
                            }}
                        >
                            {isFollowing ? "팔로잉" : "팔로우"}
                        </button>
                    </div>
                </div>

                {/* 테마 목록 */}
                <h2 className="text-[17px] font-bold mb-4" style={{ color: "#1c1c1e" }}>등록 테마 {themes.length}개</h2>

                {themes.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-16 gap-2 rounded-[20px]"
                        style={{ background: "rgba(255,255,255,0.5)" }}>
                        <p className="text-[14px]" style={{ color: "#8e8e93" }}>아직 등록된 테마가 없습니다.</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                        {themes.map((theme, idx) => (
                            <div
                                key={theme.id}
                                onClick={() => router.push(`/store/${theme.id}`)}
                                className="flex flex-col rounded-[20px] overflow-hidden transition-all hover:-translate-y-1 hover:shadow-xl cursor-pointer"
                                style={{
                                    background: "rgba(255,255,255,0.6)",
                                    border: "1px solid rgba(255,255,255,0.9)",
                                    boxShadow: "0 4px 20px rgba(0,0,0,0.06)",
                                }}
                            >
                                <div className="aspect-square relative overflow-hidden">
                                    {theme.thumbnailUrl ? (
                                        <Image src={theme.thumbnailUrl} alt={theme.title} fill className="object-cover" />
                                    ) : (
                                        <div className="w-full h-full" style={{ background: PLACEHOLDER_GRADIENTS[idx % PLACEHOLDER_GRADIENTS.length] }} />
                                    )}
                                    {theme.price === 0 && (
                                        <span className="absolute top-2.5 left-3 text-[10px] font-bold px-2 py-0.5 rounded-full"
                                            style={{ background: "#FFEF9A", color: "#1c1c1e" }}>
                                            무료
                                        </span>
                                    )}
                                </div>
                                <div className="p-4 flex flex-col gap-1">
                                    <h3 className="text-[13px] font-bold truncate" style={{ color: "#1c1c1e" }}>{theme.title}</h3>
                                    <div className="flex items-center justify-between">
                                        <span className="text-[14px] font-semibold" style={{ color: "#1c1c1e" }}>
                                            {theme.price === 0 ? "무료" : `${theme.price.toLocaleString()}원`}
                                        </span>
                                        <span className="text-[11px]" style={{ color: "#8e8e93" }}>
                                            {theme.salesCount.toLocaleString()}회 판매
                                        </span>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
            {loginModal && (
                <LoginRequiredModal
                    message="팔로우는 로그인이 필요한 기능이에요."
                    onClose={() => setLoginModal(false)}
                />
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import Image from "next/image";
import LoginRequiredModal from "../../components/LoginRequiredModal";

type Theme = {
    id: string;
    title: string;
    price: number;
    thumbnailUrl: string | null;
    tags: string[];
    salesCount: number;
    createdAt: string;
};

type Creator = {
    id: string;
    nickname: string | null;
    name: string;
    avatarUrl: string | null;
    image: string | null;
    role: string;
    createdAt: string;
};

const PLACEHOLDER_GRADIENTS = [
    "linear-gradient(135deg,#e0c3fc,#9d4edd)",
    "linear-gradient(135deg,#90e0ef,#0077b6)",
    "linear-gradient(135deg,#ffcb77,#f83600)",
    "linear-gradient(135deg,#b7e4c7,#1b4332)",
    "linear-gradient(135deg,#ffd6e7,#ff8fab)",
];

export default function CreatorProfileClient({ creatorId }: { creatorId: string }) {
    const router = useRouter();
    const [creator, setCreator] = useState<Creator | null>(null);
    const [themes, setThemes] = useState<Theme[]>([]);
    const [followerCount, setFollowerCount] = useState(0);
    const [isFollowing, setIsFollowing] = useState(false);
    const [loading, setLoading] = useState(true);
    const [followLoading, setFollowLoading] = useState(false);
    const [error, setError] = useState("");
    const [loginModal, setLoginModal] = useState(false);

    useEffect(() => {
        fetch(`/api/creator/${creatorId}`)
            .then(r => r.json())
            .then((data: { creator?: Creator; themes?: Theme[]; followerCount?: number; isFollowing?: boolean; error?: string }) => {
                if (data.error) {
                    setError(data.error);
                    return;
                }
                setCreator(data.creator ?? null);
                setThemes(data.themes ?? []);
                setFollowerCount(data.followerCount ?? 0);
                setIsFollowing(data.isFollowing ?? false);
            })
            .catch(() => setError("크리에이터 정보를 불러올 수 없습니다."))
            .finally(() => setLoading(false));
    }, [creatorId]);

    const handleFollow = async () => {
        setFollowLoading(true);
        try {
            const res = await fetch("/api/follow", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ creatorId }),
            });
            if (res.status === 401) {
                setLoginModal(true);
                return;
            }
            const data = await res.json() as { isFollowing?: boolean; error?: string };
            if (data.isFollowing !== undefined) {
                setIsFollowing(data.isFollowing);
                setFollowerCount(prev => data.isFollowing ? prev + 1 : Math.max(0, prev - 1));
            }
        } catch { /* ignore */ } finally {
            setFollowLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <span className="text-[14px]" style={{ color: "#8e8e93" }}>불러오는 중...</span>
            </div>
        );
    }

    if (error || !creator) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center gap-3">
                <p className="text-[16px]" style={{ color: "#1c1c1e" }}>사용자를 찾을 수 없습니다.</p>
                <button onClick={() => router.back()} className="text-[13px]" style={{ color: "#8e8e93" }}>← 뒤로 가기</button>
            </div>
        );
    }

    const displayName = creator.nickname ?? creator.name;
    // 커스텀 업로드 사진(PRO) 우선, 없으면 역할별 기본 이미지
    const avatarSrc =
        (creator.avatarUrl && !creator.avatarUrl.startsWith("/"))
            ? creator.avatarUrl
            : (creator.role === "CREATOR" || creator.role === "ADMIN" ? "/creator.png" : "/user.png");

    return (
        <div className="min-h-screen" style={{ background: "#f3f3f3" }}>
            <div style={{ maxWidth: 900, margin: "0 auto", padding: "48px 24px" }}>
                {/* 뒤로 가기 */}
                <button
                    onClick={() => router.back()}
                    className="flex items-center gap-1.5 mb-8 text-[13px] font-medium transition-opacity hover:opacity-60"
                    style={{ color: "#8e8e93" }}
                >
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#8e8e93" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M19 12H5M12 5l-7 7 7 7" />
                    </svg>
                    뒤로 가기
                </button>

                {/* 프로필 카드 */}
                <div
                    className="rounded-[24px] p-8 mb-8"
                    style={{
                        background: "rgba(255,255,255,0.7)",
                        backdropFilter: "blur(20px)",
                        border: "1px solid rgba(255,255,255,0.9)",
                        boxShadow: "0 4px 24px rgba(0,0,0,0.06)",
                    }}
                >
                    <div className="flex items-start gap-6">
                        {/* 아바타 */}
                        <div
                            className="relative shrink-0 rounded-full overflow-hidden"
                            style={{ width: 80, height: 80, background: "#e7e5e4" }}
                        >
                            <Image src={avatarSrc} alt={displayName} fill className="object-cover" />
                        </div>

                        {/* 정보 */}
                        <div className="flex-1">
                            <div className="flex items-center gap-3 flex-wrap">
                                <h1 className="text-[22px] font-extrabold" style={{ color: "#1c1c1e" }}>{displayName}</h1>
                                {creator.role === "CREATOR" && (
                                    <span className="text-[11px] font-bold px-2 py-0.5 rounded-full" style={{ background: "rgba(255,149,0,0.12)", color: "#FF9500" }}>크리에이터</span>
                                )}
                                {creator.role === "ADMIN" && (
                                    <span className="text-[11px] font-bold px-2 py-0.5 rounded-full" style={{ background: "#FF3B30", color: "#fff" }}>관리자</span>
                                )}
                            </div>

                            <div className="flex items-center gap-6 mt-3">
                                <div className="flex flex-col">
                                    <span className="text-[20px] font-bold" style={{ color: "#1c1c1e" }}>{themes.length}</span>
                                    <span className="text-[12px]" style={{ color: "#8e8e93" }}>테마</span>
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-[20px] font-bold" style={{ color: "#1c1c1e" }}>{followerCount.toLocaleString()}</span>
                                    <span className="text-[12px]" style={{ color: "#8e8e93" }}>팔로워</span>
                                </div>
                                <div className="flex flex-col">
                                    <span className="text-[20px] font-bold" style={{ color: "#1c1c1e" }}>
                                        {themes.reduce((s, t) => s + t.salesCount, 0).toLocaleString()}
                                    </span>
                                    <span className="text-[12px]" style={{ color: "#8e8e93" }}>총 판매</span>
                                </div>
                            </div>
                        </div>

                        {/* 팔로우 버튼 */}
                        <button
                            onClick={handleFollow}
                            disabled={followLoading}
                            className="px-5 py-2 rounded-full text-[13px] font-semibold transition-all active:scale-95 shrink-0"
                            style={{
                                background: isFollowing ? "rgba(0,0,0,0.06)" : "#1c1c1e",
                                color: isFollowing ? "#3a3a3c" : "#fff",
                                border: isFollowing ? "1.5px solid rgba(0,0,0,0.12)" : "none",
                                opacity: followLoading ? 0.6 : 1,
                            }}
                        >
                            {isFollowing ? "팔로잉" : "팔로우"}
                        </button>
                    </div>
                </div>

                {/* 테마 목록 */}
                <h2 className="text-[17px] font-bold mb-4" style={{ color: "#1c1c1e" }}>등록 테마 {themes.length}개</h2>

                {themes.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-16 gap-2 rounded-[20px]"
                        style={{ background: "rgba(255,255,255,0.5)" }}>
                        <p className="text-[14px]" style={{ color: "#8e8e93" }}>아직 등록된 테마가 없습니다.</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                        {themes.map((theme, idx) => (
                            <div
                                key={theme.id}
                                onClick={() => router.push(`/store/${theme.id}`)}
                                className="flex flex-col rounded-[20px] overflow-hidden transition-all hover:-translate-y-1 hover:shadow-xl cursor-pointer"
                                style={{
                                    background: "rgba(255,255,255,0.6)",
                                    border: "1px solid rgba(255,255,255,0.9)",
                                    boxShadow: "0 4px 20px rgba(0,0,0,0.06)",
                                }}
                            >
                                <div className="aspect-square relative overflow-hidden">
                                    {theme.thumbnailUrl ? (
                                        <Image src={theme.thumbnailUrl} alt={theme.title} fill className="object-cover" />
                                    ) : (
                                        <div className="w-full h-full" style={{ background: PLACEHOLDER_GRADIENTS[idx % PLACEHOLDER_GRADIENTS.length] }} />
                                    )}
                                    {theme.price === 0 && (
                                        <span className="absolute top-2.5 left-3 text-[10px] font-bold px-2 py-0.5 rounded-full"
                                            style={{ background: "#FFEF9A", color: "#1c1c1e" }}>
                                            무료
                                        </span>
                                    )}
                                </div>
                                <div className="p-4 flex flex-col gap-1">
                                    <h3 className="text-[13px] font-bold truncate" style={{ color: "#1c1c1e" }}>{theme.title}</h3>
                                    <div className="flex items-center justify-between">
                                        <span className="text-[14px] font-semibold" style={{ color: "#1c1c1e" }}>
                                            {theme.price === 0 ? "무료" : `${theme.price.toLocaleString()}원`}
                                        </span>
                                        <span className="text-[11px]" style={{ color: "#8e8e93" }}>
                                            {theme.salesCount.toLocaleString()}회 판매
                                        </span>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
            {loginModal && (
                <LoginRequiredModal
                    message="팔로우는 로그인이 필요한 기능이에요."
                    onClose={() => setLoginModal(false)}
                />
            )}
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { useParams, useRouter } from "next/navigation";
import Header from "@/app/components/Header";
import Footer from "@/app/components/Footer";
import Image from "next/image";
import Link from "next/link";

type Comment = {
    id: string; content: string; isDeleted: boolean; createdAt: string; parentId: string | null;
    userId: string; userNickname: string | null; userName: string;
    userAvatar: string | null; userImage: string | null;
    reportCount: number; myReported: boolean;
};
type PostDetail = {
    id: string; userId: string; themeName: string; description: string | null;
    images: string[]; storeLink: string | null; themeId: string | null; createdAt: string;
    userNickname: string | null; userName: string; userAvatar: string | null; userImage: string | null;
    userRole: string;
};

function timeAgo(iso: string) {
    const diff = Date.now() - new Date(iso).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1) return "방금 전";
    if (m < 60) return `${m}분 전`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}시간 전`;
    const d = Math.floor(h / 24);
    if (d < 7) return `${d}일 전`;
    const dt = new Date(iso);
    return `${dt.getFullYear()}.${String(dt.getMonth() + 1).padStart(2, "0")}.${String(dt.getDate()).padStart(2, "0")}`;
}

function Avatar({ avatar, image, name, size = 32 }: { avatar: string | null; image: string | null; name: string; size?: number }) {
    const src = avatar ?? image ?? null;
    if (src) return <Image src={src} alt={name} width={size} height={size} className="rounded-full object-cover" style={{ width: size, height: size }} />;
    return (
        <div className="rounded-full flex items-center justify-center text-white font-bold"
            style={{ width: size, height: size, background: "linear-gradient(135deg,#FF9500,#FF6B00)", fontSize: size * 0.38 }}>
            {name.slice(0, 1)}
        </div>
    );
}

function Toast({ msg }: { msg: string }) {
    return (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-full text-[13px] font-medium shadow-lg"
            style={{ background: "#1c1917", color: "#fafaf9" }}>
            {msg}
        </div>
    );
}

// ── 댓글 아이템 ───────────────────────────────────
function CommentItem({
    comment, myId, isPostOwner, depth,
    onDelete, onReport, onReply,
    replies,
}: {
    comment: Comment; myId: string | null; isPostOwner: boolean; depth: number;
    onDelete: (id: string) => void;
    onReport: (id: string) => void;
    onReply: (parentId: string, parentName: string) => void;
    replies: Comment[];
}) {
    const name = comment.userNickname ?? comment.userName;
    const canDelete = myId === comment.userId || isPostOwner;
    const canReport = !!myId && myId !== comment.userId;

    return (
        <div>
            <div className="flex items-start gap-3 py-3.5" style={{
                borderBottom: depth === 0 && replies.length === 0 ? "1px solid #f5f5f4" : "none",
                paddingLeft: depth > 0 ? 40 : 0,
            }}>
                {comment.isDeleted ? (
                    <p className="text-[13px] py-1 ml-1" style={{ color: "#d6d3d1" }}>삭제된 댓글입니다.</p>
                ) : (
                    <>
                        {depth > 0 && (
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="shrink-0 mt-1">
                                <path d="M9 18l6-6-6-6"/>
                            </svg>
                        )}
                        <Link href={`/creator/${comment.userId}`} className="shrink-0">
                            <Avatar avatar={comment.userAvatar} image={comment.userImage} name={name} role={comment.userRole} size={28} />
                        </Link>
                        <Avatar avatar={comment.userAvatar} image={comment.userImage} name={name} size={28} />
                                    {name}
                                </Link>
                                <span className="text-[11px]" style={{ color: "#d6d3d1" }}>{timeAgo(comment.createdAt)}</span>
                            </div>
                                <span className="text-[13px] font-semibold" style={{ color: "#1c1917" }}>{name}</span>
                                    className="mt-1.5 text-[11px] font-medium transition-opacity hover:opacity-60"
                                    style={{ color: "#a8a29e" }}>
                                    답글
                                </button>
                            )}
                        </div>
                        <div className="flex items-center gap-2 shrink-0">
                            {canDelete && (
                                <button onClick={() => onDelete(comment.id)}
                                    className="text-[11px] transition-opacity hover:opacity-60"
                                    style={{ color: "#d6d3d1" }}>삭제</button>
                            )}
                            {canReport && (
                                <button onClick={() => !comment.myReported && onReport(comment.id)}
                                    disabled={comment.myReported}
                                    className="text-[11px] transition-opacity hover:opacity-60 disabled:opacity-30"
                                    style={{ color: comment.myReported ? "#d6d3d1" : "#a8a29e" }}>
                                    {comment.myReported ? "신고됨" : "신고"}
                                </button>
                            )}
                        </div>
                    </>
                )}
            </div>

            {/* 대댓글 */}
            {replies.length > 0 && (
                <div style={{ borderBottom: "1px solid #f5f5f4" }}>
                    {replies.map((r) => (
                        <CommentItem key={r.id} comment={r} myId={myId} isPostOwner={isPostOwner}
                            depth={1} onDelete={onDelete} onReport={onReport} onReply={onReply} replies={[]} />
                    ))}
                </div>
            )}
        </div>
    );
}

// ── 메인 페이지 ──────────────────────────────────
export default function GalleryDetailPage() {
    const params = useParams<{ id: string }>();
    const router = useRouter();
    const postId = params.id;

    const [post, setPost] = useState<PostDetail | null>(null);
    const [comments, setComments] = useState<Comment[]>([]);
    const [loading, setLoading] = useState(true);
    const [myId, setMyId] = useState<string | null>(null);
    const [commentText, setCommentText] = useState("");
    const [submitting, setSubmitting] = useState(false);
    const [imgIndex, setImgIndex] = useState(0);
    const [toast, setToast] = useState<string | null>(null);

    // 대댓글 관련
    const [replyTo, setReplyTo] = useState<{ parentId: string; parentName: string } | null>(null);

    // 수정 관련
    const [editing, setEditing] = useState(false);
    const [editName, setEditName] = useState("");
    const [editDesc, setEditDesc] = useState("");
    const [editSaving, setEditSaving] = useState(false);

    const showToast = (msg: string) => { setToast(msg); setTimeout(() => setToast(null), 2500); };

    useEffect(() => {
        fetch("/api/auth/session").then((r) => r.json()).then((d) => {
            if (d?.session) setMyId(d.session.dbId ?? null);
        }).catch(() => {});
    }, []);

    const fetchPost = useCallback(async () => {
        try {
            const res = await fetch(`/api/gallery/${postId}`);
            if (!res.ok) { router.replace("/gallery"); return; }
            const data = await res.json() as { post: PostDetail; comments: Comment[] };
            setPost(data.post);
            setComments(data.comments);
            setEditName(data.post.themeName);
            setEditDesc(data.post.description ?? "");
        } finally {
            setLoading(false);
        }
    }, [postId, router]);

    useEffect(() => { fetchPost(); }, [fetchPost]);

    const handleLike = async () => {
        if (!myId || !post) return;
        const res = await fetch(`/api/gallery/${postId}/like`, { method: "POST" });
        const data = await res.json() as { liked: boolean };
        setPost((p) => p ? { ...p, liked: data.liked, likeCount: p.likeCount + (data.liked ? 1 : -1) } : p);
    };

    const handleComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!commentText.trim() || !myId) return;
        setSubmitting(true);
        try {
            const body: { content: string; parentId?: string } = { content: commentText.trim() };
            if (replyTo) body.parentId = replyTo.parentId;
            const res = await fetch(`/api/gallery/${postId}/comments`, {
                method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body),
            });
            if (res.ok) {
                const data = await res.json() as { comment: Comment };
                setComments((prev) => [...prev, data.comment]);
                setCommentText("");
                setReplyTo(null);
            }
        } finally {
            setSubmitting(false);
        }
    };

    const handleDeleteComment = async (commentId: string) => {
        const res = await fetch(`/api/gallery/${postId}/comments/${commentId}`, { method: "DELETE" });
        if (res.ok) setComments((prev) => prev.map((c) => c.id === commentId ? { ...c, isDeleted: true } : c));
    };

    const handleReportComment = async (commentId: string) => {
        const res = await fetch(`/api/gallery/${postId}/comments/${commentId}`, { method: "POST" });
        if (res.ok) {
            setComments((prev) => prev.map((c) => c.id === commentId ? { ...c, myReported: true } : c));
            showToast("신고가 접수되었어요");
        } else {
            const d = await res.json() as { error?: string };
            showToast(d.error ?? "오류가 발생했습니다.");
        }
    };

    const handleDeletePost = async () => {
        if (!confirm("게시글을 삭제하시겠습니까?")) return;
        const res = await fetch(`/api/gallery/${postId}`, { method: "DELETE" });
        if (res.ok) router.replace("/gallery");
    };

    const handleSaveEdit = async () => {
        if (!editName.trim()) return;
        setEditSaving(true);
        try {
            const res = await fetch(`/api/gallery/${postId}`, {
                method: "PATCH", headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ themeName: editName.trim(), description: editDesc.trim() }),
            });
            if (res.ok) {
                setPost((p) => p ? { ...p, themeName: editName.trim(), description: editDesc.trim() || null } : p);
                setEditing(false);
                showToast("수정됐어요");
            }
        } finally {
            setEditSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
                <Header />
                <div className="flex-1 flex items-center justify-center">
                    <div className="w-6 h-6 rounded-full border-2 border-stone-200 border-t-stone-400 animate-spin" />
                </div>
            </div>
        );
    }
    if (!post) return null;

    const displayName = post.userNickname ?? post.userName;
    const isOwner = myId === post.userId;

    // 댓글 트리 구성 (최상위 댓글만, 대댓글은 replies로)
    const topComments = comments.filter((c) => !c.parentId);
    const getReplies = (parentId: string) => comments.filter((c) => c.parentId === parentId);
    const visibleCount = comments.filter((c) => !c.isDeleted).length;

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
            <Header />
            <div className="flex-1 max-w-[720px] mx-auto w-full px-5 pt-12 pb-24">

                {/* 뒤로 */}
                <button onClick={() => router.back()}
                    className="flex items-center gap-1.5 text-[13px] mb-8 transition-opacity hover:opacity-60"
                    style={{ color: "#a8a29e" }}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M19 12H5"/><path d="M12 19l-7-7 7-7"/>
                    </svg>
                    갤러리
                </button>

                {/* 작성자 + 수정/삭제 */}
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-3">
                        <Link href={`/creator/${post.userId}`}>
                            <Avatar avatar={post.userAvatar} image={post.userImage} name={displayName} role={post.userRole} size={40} />
                        </Link>
                        <div>
                            <Link href={`/creator/${post.userId}`} className="text-[14px] font-semibold hover:underline" style={{ color: "#1c1917" }}>
                                {displayName}
                            </Link>
                            <p className="text-[12px]" style={{ color: "#a8a29e" }}>{timeAgo(post.createdAt)}</p>
                        </div>
                    </div>
                        <Avatar avatar={post.userAvatar} image={post.userImage} name={displayName} size={40} />
                                className="text-[12px] font-medium transition-opacity hover:opacity-60"
                                style={{ color: "#a8a29e" }}>
                            <p className="text-[14px] font-semibold" style={{ color: "#1c1917" }}>{displayName}</p>
                                style={{ color: "#FF3B30" }}>
                                삭제
                            </button>
                        </div>
                    )}
                </div>

                {/* 이미지 슬라이더 */}
                <div className="relative rounded-2xl overflow-hidden mb-6" style={{ background: "#e7e5e4" }}>
                    <div className="relative w-full" style={{ paddingBottom: "75%" }}>
                        <Image src={post.images[imgIndex]} alt={post.themeName} fill className="object-cover" />
                    </div>
                    {post.images.length > 1 && (
                        <>
                            {imgIndex > 0 && (
                                <button onClick={() => setImgIndex((v) => v - 1)}
                                    className="absolute left-3 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center"
                                    style={{ background: "rgba(0,0,0,0.4)" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round"><path d="M15 18l-6-6 6-6"/></svg>
                                </button>
                            )}
                            {imgIndex < post.images.length - 1 && (
                                <button onClick={() => setImgIndex((v) => v + 1)}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center"
                                    style={{ background: "rgba(0,0,0,0.4)" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
                                </button>
                            )}
                            <div className="absolute bottom-3 left-1/2 -translate-x-1/2 flex gap-1.5">
                                {post.images.map((_, i) => (
                                    <button key={i} onClick={() => setImgIndex(i)}
                                        className="rounded-full transition-all"
                                        style={{ width: i === imgIndex ? 16 : 6, height: 6, background: i === imgIndex ? "#fff" : "rgba(255,255,255,0.5)" }} />
                                ))}
                            </div>
                        </>
                    )}
                </div>

                {/* 제목 + 설명 (수정 모드) */}
                <div className="mb-6" style={{ borderBottom: "1px solid #e7e5e4", paddingBottom: 20 }}>
                    {editing ? (
                        <div className="flex flex-col gap-4">
                            <input value={editName} onChange={(e) => setEditName(e.target.value)} maxLength={50}
                                className="text-[20px] font-bold outline-none bg-transparent w-full"
                                style={{ color: "#1c1917", borderBottom: "1.5px solid rgb(74,123,247)", paddingBottom: 6 }} />
                            <div className="flex flex-col gap-1">
                                <textarea value={editDesc} onChange={(e) => setEditDesc(e.target.value)} maxLength={200} rows={3}
                                    placeholder="소개 (선택)"
                                    className="text-[14px] outline-none bg-transparent resize-none leading-relaxed w-full placeholder:text-[#d6d3d1]"
                                    style={{ color: "#78716c", borderBottom: "1px solid #e7e5e4", paddingBottom: 8 }} />
                                <span className="text-[11px] text-right" style={{ color: "#d6d3d1" }}>{editDesc.length}/200</span>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => setEditing(false)}
                                    className="px-4 py-2 rounded-full text-[13px] transition-opacity hover:opacity-60"
                                    style={{ background: "rgba(0,0,0,0.05)", color: "#78716c" }}>취소</button>
                                <button onClick={handleSaveEdit} disabled={editSaving || !editName.trim()}
                                    className="px-4 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70 disabled:opacity-30"
                                    style={{ background: "#1c1917", color: "#fafaf9" }}>
                                    {editSaving ? "저장 중…" : "저장"}
                                </button>
                            </div>
                        </div>
                    ) : (
                        <>
                            <h1 className="text-[22px] font-bold tracking-tight mb-2" style={{ color: "#1c1917" }}>{post.themeName}</h1>
                            {post.description && <p className="text-[14px] leading-relaxed" style={{ color: "#78716c" }}>{post.description}</p>}
                            {(post.themeId || post.storeLink) && (
                                <Link href={post.themeId ? `/store/${post.themeId}` : (post.storeLink ?? "#")}
                                    className="inline-flex items-center gap-1.5 mt-3 text-[13px] font-medium transition-opacity hover:opacity-70"
                                    style={{ color: "rgb(74,123,247)" }}>
                                    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                        <circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/>
                                        <path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/>
                                    </svg>
                                    스토어에서 보기
                                </Link>
                            )}
                        </>
                    )}
                </div>

                {/* 좋아요 (하트만) */}
                <div className="flex items-center gap-3 mb-8">
                    <button onClick={handleLike}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-full text-[13px] font-medium transition-all"
                        style={{
                            background: post.liked ? "rgba(255,59,48,0.08)" : "rgba(0,0,0,0.04)",
                            color: post.liked ? "#FF3B30" : "#78716c",
                        }}>
                        <svg width="14" height="14" viewBox="0 0 24 24"
                            fill={post.liked ? "currentColor" : "none"}
                            stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
                        </svg>
                        좋아요 {post.likeCount}
                    </button>
                </div>

                {/* 댓글 */}
                <div style={{ borderTop: "1px solid #e7e5e4" }}>
                    <p className="text-[11px] font-semibold tracking-wide uppercase py-4" style={{ color: "#a8a29e" }}>
                        댓글 {visibleCount}
                    </p>

                    {topComments.map((c) => (
                        <CommentItem
                            key={c.id}
                            comment={c}
                            myId={myId}
                            isPostOwner={isOwner}
                            depth={0}
                            onDelete={handleDeleteComment}
                            onReport={handleReportComment}
                            onReply={(parentId, parentName) => {
                                setReplyTo({ parentId, parentName });
                                setTimeout(() => document.getElementById("comment-input")?.focus(), 50);
                            }}
                            replies={getReplies(c.id)}
                        />
                    ))}

                    {/* 댓글 입력 */}
                    {myId ? (
                        <form onSubmit={handleComment} className="flex flex-col gap-2 pt-5">
                            {/* 답글 대상 표시 */}
                            {replyTo && (
                                <div className="flex items-center gap-2 px-3 py-2 rounded-lg"
                                    style={{ background: "rgba(74,123,247,0.06)" }}>
                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="rgb(74,123,247)" strokeWidth="2" strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
                                    <span className="text-[12px]" style={{ color: "rgb(74,123,247)" }}>
                                        <b>{replyTo.parentName}</b>에게 답글
                                    </span>
                                    <button type="button" onClick={() => setReplyTo(null)} className="ml-auto transition-opacity hover:opacity-60">
                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#a8a29e" strokeWidth="2.5" strokeLinecap="round"><path d="M18 6L6 18M6 6l12 12"/></svg>
                                    </button>
                                </div>
                            )}
                            <div className="flex items-end gap-3">
                                <textarea
                                    id="comment-input"
                                    value={commentText}
                                    onChange={(e) => setCommentText(e.target.value)}
                                    placeholder={replyTo ? `${replyTo.parentName}에게 답글 달기…` : "댓글을 입력하세요…"}
                                    rows={2} maxLength={200}
                                    className="flex-1 text-[14px] outline-none bg-transparent resize-none leading-relaxed placeholder:text-[#d6d3d1]"
                                    style={{ color: "#1c1917", borderBottom: "1px solid #e7e5e4", paddingBottom: 8 }}
                                    onKeyDown={(e) => {
                                        if (e.key === "Enter" && !e.shiftKey) {
                                            e.preventDefault();
                                            if (commentText.trim()) handleComment(e as unknown as React.FormEvent);
                                        }
                                    }}
                                />
                                <button type="submit" disabled={submitting || !commentText.trim()}
                                    className="shrink-0 px-4 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70 disabled:opacity-30"
                                    style={{ background: "#1c1917", color: "#fafaf9" }}>
                                    {submitting ? "…" : "등록"}
                                </button>
                            </div>
                        </form>
                    ) : (
                        <p className="text-[13px] py-4" style={{ color: "#a8a29e" }}>
                            <Link href="/api/auth/kakao" className="underline hover:opacity-70">로그인</Link> 후 댓글을 작성할 수 있어요.
                        </p>
                    )}
                </div>
            </div>

            {toast && <Toast msg={toast} />}
            <Footer />
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { useParams, useRouter } from "next/navigation";
import Header from "@/app/components/Header";
import Footer from "@/app/components/Footer";
import Image from "next/image";
import Link from "next/link";

type Comment = {
    id: string; content: string; isDeleted: boolean; createdAt: string; parentId: string | null;
    userId: string; userNickname: string | null; userName: string;
    userAvatar: string | null; userImage: string | null; userRole: string;
    reportCount: number; myReported: boolean;
};
type PostDetail = {
    id: string; userId: string; themeName: string; description: string | null;
    images: string[]; storeLink: string | null; themeId: string | null; createdAt: string;
    userNickname: string | null; userName: string; userAvatar: string | null; userImage: string | null;
    userRole: string;
    likeCount: number; commentCount: number; liked: boolean;
};

function timeAgo(iso: string) {
    const diff = Date.now() - new Date(iso).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1) return "방금 전";
    if (m < 60) return `${m}분 전`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}시간 전`;
    const d = Math.floor(h / 24);
    if (d < 7) return `${d}일 전`;
    const dt = new Date(iso);
    return `${dt.getFullYear()}.${String(dt.getMonth() + 1).padStart(2, "0")}.${String(dt.getDate()).padStart(2, "0")}`;
}

function getAvatarSrc(role: string, avatarUrl: string | null): string {
    // 커스텀 업로드 사진 (PRO 유저 - '/'로 시작하지 않는 data URL 등)
    if (avatarUrl && !avatarUrl.startsWith("/")) return avatarUrl;
    // 역할별 기본 이미지
    if (role === "CREATOR" || role === "ADMIN") return "/creator.png";
    return "/user.png";
}

function Avatar({ avatar, name, role, size = 32 }: { avatar: string | null; image?: string | null; name: string; role: string; size?: number }) {
    const src = getAvatarSrc(role, avatar);
    return (
        <Image
            src={src} alt={name} width={size} height={size}
            className="rounded-full object-cover"
            style={{ width: size, height: size }}
            unoptimized={!!avatar && !avatar.startsWith("/")}
        />
    );
}

function Toast({ msg }: { msg: string }) {
    return (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-full text-[13px] font-medium shadow-lg"
            style={{ background: "#1c1917", color: "#fafaf9" }}>
            {msg}
        </div>
    );
}

// ── 댓글 아이템 ───────────────────────────────────
function CommentItem({
    comment, myId, isPostOwner, depth,
    onDelete, onReport, onReply,
    replies,
}: {
    comment: Comment; myId: string | null; isPostOwner: boolean; depth: number;
    onDelete: (id: string) => void;
    onReport: (id: string) => void;
    onReply: (parentId: string, parentName: string) => void;
    replies: Comment[];
}) {
    const name = comment.userNickname ?? comment.userName;
    const canDelete = myId === comment.userId || isPostOwner;
    const canReport = !!myId && myId !== comment.userId;

    return (
        <div>
            <div className="flex items-start gap-3 py-3.5" style={{
                borderBottom: depth === 0 && replies.length === 0 ? "1px solid #f5f5f4" : "none",
                paddingLeft: depth > 0 ? 40 : 0,
            }}>
                {comment.isDeleted ? (
                    <p className="text-[13px] py-1 ml-1" style={{ color: "#d6d3d1" }}>삭제된 댓글입니다.</p>
                ) : (
                    <>
                        {depth > 0 && (
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="shrink-0 mt-1">
                                <path d="M9 18l6-6-6-6"/>
                            </svg>
                        )}
                        <Link href={`/creator/${comment.userId}`} className="shrink-0">
                            <Avatar avatar={comment.userAvatar} image={comment.userImage} name={name} role={comment.userRole} size={28} />
                        </Link>
                        <div className="flex-1 min-w-0">
                            <div className="flex items-baseline gap-2 mb-0.5">
                                <Link href={`/creator/${comment.userId}`} className="text-[13px] font-semibold hover:underline" style={{ color: "#1c1917" }}>
                                    {name}
                                </Link>
                                <span className="text-[11px]" style={{ color: "#d6d3d1" }}>{timeAgo(comment.createdAt)}</span>
                            </div>
                            <p className="text-[13px] leading-relaxed" style={{ color: "#78716c" }}>{comment.content}</p>
                            {/* 답글 버튼 (depth 0만) */}
                            {myId && depth === 0 && (
                                <button onClick={() => onReply(comment.id, name)}
                                    className="mt-1.5 text-[11px] font-medium transition-opacity hover:opacity-60"
                                    style={{ color: "#a8a29e" }}>
                                    답글
                                </button>
                            )}
                        </div>
                        <div className="flex items-center gap-2 shrink-0">
                            {canDelete && (
                                <button onClick={() => onDelete(comment.id)}
                                    className="text-[11px] transition-opacity hover:opacity-60"
                                    style={{ color: "#d6d3d1" }}>삭제</button>
                            )}
                            {canReport && (
                                <button onClick={() => !comment.myReported && onReport(comment.id)}
                                    disabled={comment.myReported}
                                    className="text-[11px] transition-opacity hover:opacity-60 disabled:opacity-30"
                                    style={{ color: comment.myReported ? "#d6d3d1" : "#a8a29e" }}>
                                    {comment.myReported ? "신고됨" : "신고"}
                                </button>
                            )}
                        </div>
                    </>
                )}
            </div>

            {/* 대댓글 */}
            {replies.length > 0 && (
                <div style={{ borderBottom: "1px solid #f5f5f4" }}>
                    {replies.map((r) => (
                        <CommentItem key={r.id} comment={r} myId={myId} isPostOwner={isPostOwner}
                            depth={1} onDelete={onDelete} onReport={onReport} onReply={onReply} replies={[]} />
                    ))}
                </div>
            )}
        </div>
    );
}

// ── 메인 페이지 ──────────────────────────────────
export default function GalleryDetailPage() {
    const params = useParams<{ id: string }>();
    const router = useRouter();
    const postId = params.id;

    const [post, setPost] = useState<PostDetail | null>(null);
    const [comments, setComments] = useState<Comment[]>([]);
    const [loading, setLoading] = useState(true);
    const [myId, setMyId] = useState<string | null>(null);
    const [commentText, setCommentText] = useState("");
    const [submitting, setSubmitting] = useState(false);
    const [imgIndex, setImgIndex] = useState(0);
    const [toast, setToast] = useState<string | null>(null);

    // 대댓글 관련
    const [replyTo, setReplyTo] = useState<{ parentId: string; parentName: string } | null>(null);

    // 수정 관련
    const [editing, setEditing] = useState(false);
    const [editName, setEditName] = useState("");
    const [editDesc, setEditDesc] = useState("");
    const [editSaving, setEditSaving] = useState(false);

    const showToast = (msg: string) => { setToast(msg); setTimeout(() => setToast(null), 2500); };

    useEffect(() => {
        fetch("/api/auth/session").then((r) => r.json()).then((d) => {
            if (d?.session) setMyId(d.session.dbId ?? null);
        }).catch(() => {});
    }, []);

    const fetchPost = useCallback(async () => {
        try {
            const res = await fetch(`/api/gallery/${postId}`);
            if (!res.ok) { router.replace("/gallery"); return; }
            const data = await res.json() as { post: PostDetail; comments: Comment[] };
            setPost(data.post);
            setComments(data.comments);
            setEditName(data.post.themeName);
            setEditDesc(data.post.description ?? "");
        } finally {
            setLoading(false);
        }
    }, [postId, router]);

    useEffect(() => { fetchPost(); }, [fetchPost]);

    const handleLike = async () => {
        if (!myId || !post) return;
        const res = await fetch(`/api/gallery/${postId}/like`, { method: "POST" });
        const data = await res.json() as { liked: boolean };
        setPost((p) => p ? { ...p, liked: data.liked, likeCount: p.likeCount + (data.liked ? 1 : -1) } : p);
    };

    const handleComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!commentText.trim() || !myId) return;
        setSubmitting(true);
        try {
            const body: { content: string; parentId?: string } = { content: commentText.trim() };
            if (replyTo) body.parentId = replyTo.parentId;
            const res = await fetch(`/api/gallery/${postId}/comments`, {
                method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body),
            });
            if (res.ok) {
                const data = await res.json() as { comment: Comment };
                setComments((prev) => [...prev, data.comment]);
                setCommentText("");
                setReplyTo(null);
            }
        } finally {
            setSubmitting(false);
        }
    };

    const handleDeleteComment = async (commentId: string) => {
        const res = await fetch(`/api/gallery/${postId}/comments/${commentId}`, { method: "DELETE" });
        if (res.ok) setComments((prev) => prev.map((c) => c.id === commentId ? { ...c, isDeleted: true } : c));
    };

    const handleReportComment = async (commentId: string) => {
        const res = await fetch(`/api/gallery/${postId}/comments/${commentId}`, { method: "POST" });
        if (res.ok) {
            setComments((prev) => prev.map((c) => c.id === commentId ? { ...c, myReported: true } : c));
            showToast("신고가 접수되었어요");
        } else {
            const d = await res.json() as { error?: string };
            showToast(d.error ?? "오류가 발생했습니다.");
        }
    };

    const handleDeletePost = async () => {
        if (!confirm("게시글을 삭제하시겠습니까?")) return;
        const res = await fetch(`/api/gallery/${postId}`, { method: "DELETE" });
        if (res.ok) router.replace("/gallery");
    };

    const handleSaveEdit = async () => {
        if (!editName.trim()) return;
        setEditSaving(true);
        try {
            const res = await fetch(`/api/gallery/${postId}`, {
                method: "PATCH", headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ themeName: editName.trim(), description: editDesc.trim() }),
            });
            if (res.ok) {
                setPost((p) => p ? { ...p, themeName: editName.trim(), description: editDesc.trim() || null } : p);
                setEditing(false);
                showToast("수정됐어요");
            }
        } finally {
            setEditSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
                <Header />
                <div className="flex-1 flex items-center justify-center">
                    <div className="w-6 h-6 rounded-full border-2 border-stone-200 border-t-stone-400 animate-spin" />
                </div>
            </div>
        );
    }
    if (!post) return null;

    const displayName = post.userNickname ?? post.userName;
    const isOwner = myId === post.userId;

    // 댓글 트리 구성 (최상위 댓글만, 대댓글은 replies로)
    const topComments = comments.filter((c) => !c.parentId);
    const getReplies = (parentId: string) => comments.filter((c) => c.parentId === parentId);
    const visibleCount = comments.filter((c) => !c.isDeleted).length;

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
            <Header />
            <div className="flex-1 max-w-[720px] mx-auto w-full px-5 pt-12 pb-24">

                {/* 뒤로 */}
                <button onClick={() => router.back()}
                    className="flex items-center gap-1.5 text-[13px] mb-8 transition-opacity hover:opacity-60"
                    style={{ color: "#a8a29e" }}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                        <path d="M19 12H5"/><path d="M12 19l-7-7 7-7"/>
                    </svg>
                    갤러리
                </button>

                {/* 작성자 + 수정/삭제 */}
                <div className="flex items-center justify-between mb-6">
                    <div className="flex items-center gap-3">
                        <Link href={`/creator/${post.userId}`}>
                            <Avatar avatar={post.userAvatar} image={post.userImage} name={displayName} role={post.userRole} size={40} />
                        </Link>
                        <div>
                            <Link href={`/creator/${post.userId}`} className="text-[14px] font-semibold hover:underline" style={{ color: "#1c1917" }}>
                                {displayName}
                            </Link>
                            <p className="text-[12px]" style={{ color: "#a8a29e" }}>{timeAgo(post.createdAt)}</p>
                        </div>
                    </div>
                    {isOwner && (
                        <div className="flex items-center gap-3">
                            <button onClick={() => { setEditing(true); setEditName(post.themeName); setEditDesc(post.description ?? ""); }}
                                className="text-[12px] font-medium transition-opacity hover:opacity-60"
                                style={{ color: "#a8a29e" }}>
                                수정
                            </button>
                            <button onClick={handleDeletePost}
                                className="text-[12px] transition-opacity hover:opacity-60"
                                style={{ color: "#FF3B30" }}>
                                삭제
                            </button>
                        </div>
                    )}
                </div>

                {/* 이미지 슬라이더 */}
                <div className="relative rounded-2xl overflow-hidden mb-6" style={{ background: "#e7e5e4" }}>
                    <div className="relative w-full" style={{ paddingBottom: "75%" }}>
                        <Image src={post.images[imgIndex]} alt={post.themeName} fill className="object-cover" />
                    </div>
                    {post.images.length > 1 && (
                        <>
                            {imgIndex > 0 && (
                                <button onClick={() => setImgIndex((v) => v - 1)}
                                    className="absolute left-3 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center"
                                    style={{ background: "rgba(0,0,0,0.4)" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round"><path d="M15 18l-6-6 6-6"/></svg>
                                </button>
                            )}
                            {imgIndex < post.images.length - 1 && (
                                <button onClick={() => setImgIndex((v) => v + 1)}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full flex items-center justify-center"
                                    style={{ background: "rgba(0,0,0,0.4)" }}>
                                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
                                </button>
                            )}
                            <div className="absolute bottom-3 left-1/2 -translate-x-1/2 flex gap-1.5">
                                {post.images.map((_, i) => (
                                    <button key={i} onClick={() => setImgIndex(i)}
                                        className="rounded-full transition-all"
                                        style={{ width: i === imgIndex ? 16 : 6, height: 6, background: i === imgIndex ? "#fff" : "rgba(255,255,255,0.5)" }} />
                                ))}
                            </div>
                        </>
                    )}
                </div>

                {/* 제목 + 설명 (수정 모드) */}
                <div className="mb-6" style={{ borderBottom: "1px solid #e7e5e4", paddingBottom: 20 }}>
                    {editing ? (
                        <div className="flex flex-col gap-4">
                            <input value={editName} onChange={(e) => setEditName(e.target.value)} maxLength={50}
                                className="text-[20px] font-bold outline-none bg-transparent w-full"
                                style={{ color: "#1c1917", borderBottom: "1.5px solid rgb(74,123,247)", paddingBottom: 6 }} />
                            <div className="flex flex-col gap-1">
                                <textarea value={editDesc} onChange={(e) => setEditDesc(e.target.value)} maxLength={200} rows={3}
                                    placeholder="소개 (선택)"
                                    className="text-[14px] outline-none bg-transparent resize-none leading-relaxed w-full placeholder:text-[#d6d3d1]"
                                    style={{ color: "#78716c", borderBottom: "1px solid #e7e5e4", paddingBottom: 8 }} />
                                <span className="text-[11px] text-right" style={{ color: "#d6d3d1" }}>{editDesc.length}/200</span>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => setEditing(false)}
                                    className="px-4 py-2 rounded-full text-[13px] transition-opacity hover:opacity-60"
                                    style={{ background: "rgba(0,0,0,0.05)", color: "#78716c" }}>취소</button>
                                <button onClick={handleSaveEdit} disabled={editSaving || !editName.trim()}
                                    className="px-4 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70 disabled:opacity-30"
                                    style={{ background: "#1c1917", color: "#fafaf9" }}>
                                    {editSaving ? "저장 중…" : "저장"}
                                </button>
                            </div>
                        </div>
                    ) : (
                        <>
                            <h1 className="text-[22px] font-bold tracking-tight mb-2" style={{ color: "#1c1917" }}>{post.themeName}</h1>
                            {post.description && <p className="text-[14px] leading-relaxed" style={{ color: "#78716c" }}>{post.description}</p>}
                            {(post.themeId || post.storeLink) && (
                                <Link href={post.themeId ? `/store/${post.themeId}` : (post.storeLink ?? "#")}
                                    className="inline-flex items-center gap-1.5 mt-3 text-[13px] font-medium transition-opacity hover:opacity-70"
                                    style={{ color: "rgb(74,123,247)" }}>
                                    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                        <circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/>
                                        <path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/>
                                    </svg>
                                    스토어에서 보기
                                </Link>
                            )}
                        </>
                    )}
                </div>

                {/* 좋아요 (하트만) */}
                <div className="flex items-center gap-3 mb-8">
                    <button onClick={handleLike}
                        className="flex items-center gap-1.5 px-4 py-2 rounded-full text-[13px] font-medium transition-all"
                        style={{
                            background: post.liked ? "rgba(255,59,48,0.08)" : "rgba(0,0,0,0.04)",
                            color: post.liked ? "#FF3B30" : "#78716c",
                        }}>
                        <svg width="14" height="14" viewBox="0 0 24 24"
                            fill={post.liked ? "currentColor" : "none"}
                            stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
                        </svg>
                        좋아요 {post.likeCount}
                    </button>
                </div>

                {/* 댓글 */}
                <div style={{ borderTop: "1px solid #e7e5e4" }}>
                    <p className="text-[11px] font-semibold tracking-wide uppercase py-4" style={{ color: "#a8a29e" }}>
                        댓글 {visibleCount}
                    </p>

                    {topComments.map((c) => (
                        <CommentItem
                            key={c.id}
                            comment={c}
                            myId={myId}
                            isPostOwner={isOwner}
                            depth={0}
                            onDelete={handleDeleteComment}
                            onReport={handleReportComment}
                            onReply={(parentId, parentName) => {
                                setReplyTo({ parentId, parentName });
                                setTimeout(() => document.getElementById("comment-input")?.focus(), 50);
                            }}
                            replies={getReplies(c.id)}
                        />
                    ))}

                    {/* 댓글 입력 */}
                    {myId ? (
                        <form onSubmit={handleComment} className="flex flex-col gap-2 pt-5">
                            {/* 답글 대상 표시 */}
                            {replyTo && (
                                <div className="flex items-center gap-2 px-3 py-2 rounded-lg"
                                    style={{ background: "rgba(74,123,247,0.06)" }}>
                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="rgb(74,123,247)" strokeWidth="2" strokeLinecap="round"><path d="M9 18l6-6-6-6"/></svg>
                                    <span className="text-[12px]" style={{ color: "rgb(74,123,247)" }}>
                                        <b>{replyTo.parentName}</b>에게 답글
                                    </span>
                                    <button type="button" onClick={() => setReplyTo(null)} className="ml-auto transition-opacity hover:opacity-60">
                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#a8a29e" strokeWidth="2.5" strokeLinecap="round"><path d="M18 6L6 18M6 6l12 12"/></svg>
                                    </button>
                                </div>
                            )}
                            <div className="flex items-end gap-3">
                                <textarea
                                    id="comment-input"
                                    value={commentText}
                                    onChange={(e) => setCommentText(e.target.value)}
                                    placeholder={replyTo ? `${replyTo.parentName}에게 답글 달기…` : "댓글을 입력하세요…"}
                                    rows={2} maxLength={200}
                                    className="flex-1 text-[14px] outline-none bg-transparent resize-none leading-relaxed placeholder:text-[#d6d3d1]"
                                    style={{ color: "#1c1917", borderBottom: "1px solid #e7e5e4", paddingBottom: 8 }}
                                    onKeyDown={(e) => {
                                        if (e.key === "Enter" && !e.shiftKey) {
                                            e.preventDefault();
                                            if (commentText.trim()) handleComment(e as unknown as React.FormEvent);
                                        }
                                    }}
                                />
                                <button type="submit" disabled={submitting || !commentText.trim()}
                                    className="shrink-0 px-4 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70 disabled:opacity-30"
                                    style={{ background: "#1c1917", color: "#fafaf9" }}>
                                    {submitting ? "…" : "등록"}
                                </button>
                            </div>
                        </form>
                    ) : (
                        <p className="text-[13px] py-4" style={{ color: "#a8a29e" }}>
                            <Link href="/api/auth/kakao" className="underline hover:opacity-70">로그인</Link> 후 댓글을 작성할 수 있어요.
                        </p>
                    )}
                </div>
            </div>

            {toast && <Toast msg={toast} />}
            <Footer />
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import Header from "@/app/components/Header";
import Footer from "@/app/components/Footer";
import Image from "next/image";
import Link from "next/link";
import { useRouter } from "next/navigation";

// ── 타입 ──────────────────────────────────────────
type GalleryPost = {
    id: string; userId: string; themeName: string; description: string | null;
    images: string[]; storeLink: string | null; themeId: string | null;
    createdAt: string; liked: boolean; likeCount: number; commentCount: number;
    userNickname: string | null; userName: string; userAvatar: string | null; userImage: string | null;
};

function timeAgo(iso: string) {
    const diff = Date.now() - new Date(iso).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1) return "방금 전";
    if (m < 60) return `${m}분 전`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}시간 전`;
    const d = Math.floor(h / 24);
    if (d < 7) return `${d}일 전`;
    const dt = new Date(iso);
    return `${dt.getFullYear()}.${String(dt.getMonth() + 1).padStart(2, "0")}.${String(dt.getDate()).padStart(2, "0")}`;
}

function Avatar({ avatar, image, name, size = 32 }: { avatar: string | null; image: string | null; name: string; size?: number }) {
    const src = avatar ?? image ?? null;
    if (src) return <Image src={src} alt={name} width={size} height={size} className="rounded-full object-cover" style={{ width: size, height: size }} />;
            src={fallbackSrc} alt={name} width={size} height={size}
            className="rounded-full object-cover"
            style={{ width: size, height: size, cursor: onClick ? "pointer" : "default" }}
            onClick={onClick}
        />
    );
}

// ── 게시글 카드 ──────────────────────────────────
function PostCard({ post, myId, onLike, onNavigate }: {
    post: GalleryPost; myId: string | null;
    onLike: (id: string) => void;
    onNavigate: (id: string) => void;
}) {
    const displayName = post.userNickname ?? post.userName;

    return (
        <div
        <div className="rounded-full flex items-center justify-center text-white font-bold"
            style={{ width: size, height: size, background: "linear-gradient(135deg,#FF9500,#FF6B00)", fontSize: size * 0.38 }}>
            {name.slice(0, 1)}
        </div>
                {post.images[0] && (
function PostCard({ post, myId, onLike }: {
                )}
                {post.images.length > 1 && (
                        style={{ background: "rgba(0,0,0,0.45)" }}>
        <Link href={`/gallery/${post.id}`} className="block group">
            <div className="rounded-2xl overflow-hidden transition-all duration-200 hover:shadow-md"
                style={{ background: "#fff", border: "1px solid rgba(0,0,0,0.06)" }}>
                {/* 이미지 */}
                <div className="relative w-full" style={{ paddingBottom: "100%", background: "#f5f5f5" }}>
                    {post.images[0] && (
                        <Image src={post.images[0]} alt={post.themeName} fill className="object-cover" />
                    )}
                    {post.images.length > 1 && (
                        <div className="absolute top-2 right-2 w-5 h-5 rounded-full flex items-center justify-center"
                            style={{ background: "rgba(0,0,0,0.45)" }}>
                            <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                <rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/>
                            </svg>
                        </div>
                    )}
                </div>
                </div>
                {/* 좋아요 + 댓글 */}
                {/* 하단 정보 */}
                <div className="px-3 py-2.5 flex items-center justify-between gap-2">
                    {/* 프사 + 닉네임 + 시간 */}
                    <div className="flex items-center gap-2 min-w-0">
                        <Avatar avatar={post.userAvatar} image={post.userImage} name={displayName} size={22} />
                        <span className="text-[12px] font-medium truncate" style={{ color: "#78716c" }}>{displayName}</span>
                        <span className="text-[11px] shrink-0" style={{ color: "#d6d3d1" }}>{timeAgo(post.createdAt)}</span>
                    </div>
                    {/* 좋아요 + 댓글 */}
                    <div className="flex items-center gap-2.5 shrink-0">
                        <button
                            onClick={(e) => { e.preventDefault(); if (myId) onLike(post.id); }}
                            className="flex items-center gap-0.5 transition-opacity hover:opacity-60"
                            style={{ color: post.liked ? "#FF3B30" : "#c8c4c0" }}>
                            <svg width="13" height="13" viewBox="0 0 24 24" fill={post.liked ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
                            </svg>
                            <span className="text-[11px]">{post.likeCount}</span>
                        </button>
                        <div className="flex items-center gap-0.5" style={{ color: "#c8c4c0" }}>
                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
                            </svg>
                            <span className="text-[11px]">{post.commentCount}</span>
                        </div>
                    </div>
                </div>
            </div>
        </Link>
        } finally {
            setLoading(false);
        }
    }, [sort]);

    useEffect(() => {
        setPage(1);
        fetchPosts(1, sort);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [sort]);

    const handleLike = async (postId: string) => {
        if (!myId) return;
        const res = await fetch(`/api/gallery/${postId}/like`, { method: "POST" });
        const data = await res.json() as { liked: boolean };
        setPosts((prev) => prev.map((p) =>
            p.id === postId ? { ...p, liked: data.liked, likeCount: p.likeCount + (data.liked ? 1 : -1) } : p
        ));
    };

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
            <Header />
            <div className="flex-1 max-w-[1200px] mx-auto w-full px-5 pt-12 pb-24">
                {/* 헤더 */}
                <div className="flex items-end justify-between mb-10">
                    <div>
                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-2" style={{ color: "#a8a29e" }}>Gallery</p>
                        <h1 className="text-[28px] font-bold tracking-tight" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>꾸미 갤러리</h1>
                        <p className="text-[14px] mt-1" style={{ color: "#78716c" }}>카꾸미로 만든 테마를 소개해보세요!</p>
                    </div>
                    {isLoggedIn && (
                        <button
                            onClick={() => router.push("/gallery/new")}
                            className="flex items-center gap-1.5 px-5 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70"
                            style={{ background: "#1c1917", color: "#fafaf9" }}>
                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>
                            테마 소개하기
                        </button>
                    )}
                </div>

                {/* 정렬 탭 */}
                <div className="flex items-center gap-1.5 mb-8">
                    {(["latest", "likes"] as const).map((s) => (
                        <button key={s} onClick={() => setSort(s)}
                            className="px-4 py-1.5 rounded-full text-[13px] font-medium transition-all duration-150"
                            style={{
                                backgroundColor: sort === s ? "rgb(74,123,247)" : "transparent",
                                color: sort === s ? "#fff" : "#78716c",
                                border: `1px solid ${sort === s ? "rgb(74,123,247)" : "#e7e5e4"}`,
                            }}>
                            {s === "latest" ? "최신순" : "좋아요순"}
                        </button>
                    ))}
                </div>

                {/* 그리드 */}
                {loading && posts.length === 0 ? (
                    <div className="flex justify-center items-center py-32">
                        <div className="w-6 h-6 rounded-full border-2 border-stone-200 border-t-stone-400 animate-spin" />
                    </div>
                ) : posts.length === 0 ? (
                    <div className="flex flex-col items-center gap-4 py-32">
                        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18M9 21V9"/>
                        </svg>
                        <p className="text-[14px]" style={{ color: "#a8a29e" }}>아직 게시글이 없어요. 첫 번째로 소개해보세요!</p>
                    </div>
                ) : (
                    <div className="grid gap-4" style={{ gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))" }}>
                        {posts.map((post) => (
                            <PostCard key={post.id} post={post} myId={myId} onLike={handleLike} />
                            <PostCard key={post.id} post={post} myId={myId} onLike={handleLike} onNavigate={(id) => router.push(`/gallery/${id}`)} />
                        ))}
                    </div>
                )}

                {/* 더보기 */}
                {posts.length < total && !loading && (
                    <div className="flex justify-center mt-10">
                        <button onClick={() => { const next = page + 1; setPage(next); fetchPosts(next); }}
                            className="px-6 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-60"
                            style={{ border: "1px solid #e7e5e4", color: "#78716c" }}>
                            더 보기
                        </button>
                    </div>
                )}
            </div>
            <Footer />
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import Header from "@/app/components/Header";
import Footer from "@/app/components/Footer";
import Image from "next/image";
import Link from "next/link";
import { useRouter } from "next/navigation";

// ── 타입 ──────────────────────────────────────────
type GalleryPost = {
    id: string; userId: string; themeName: string; description: string | null;
    images: string[]; storeLink: string | null; themeId: string | null;
    createdAt: string; liked: boolean; likeCount: number; commentCount: number;
    userNickname: string | null; userName: string; userAvatar: string | null; userImage: string | null;
    userRole: string;
};

function timeAgo(iso: string) {
    const diff = Date.now() - new Date(iso).getTime();
    const m = Math.floor(diff / 60000);
    if (m < 1) return "방금 전";
    if (m < 60) return `${m}분 전`;
    const h = Math.floor(m / 60);
    if (h < 24) return `${h}시간 전`;
    const d = Math.floor(h / 24);
    if (d < 7) return `${d}일 전`;
    const dt = new Date(iso);
    return `${dt.getFullYear()}.${String(dt.getMonth() + 1).padStart(2, "0")}.${String(dt.getDate()).padStart(2, "0")}`;
}

function getAvatarSrc(role: string, avatarUrl: string | null): string {
    // 커스텀 업로드 사진 (PRO 유저 - '/'로 시작하지 않는 data URL 등)
    if (avatarUrl && !avatarUrl.startsWith("/")) return avatarUrl;
    // 역할별 기본 이미지
    if (role === "CREATOR" || role === "ADMIN") return "/creator.png";
    return "/user.png";
}

function Avatar({ avatar, name, role, size = 32, onClick }: { avatar: string | null; image?: string | null; name: string; role: string; size?: number; onClick?: (e: React.MouseEvent) => void }) {
    const src = getAvatarSrc(role, avatar);
    return (
        <Image
            src={src} alt={name} width={size} height={size}
            className="rounded-full object-cover"
            style={{ width: size, height: size, cursor: onClick ? "pointer" : "default" }}
            onClick={onClick}
            unoptimized={!!avatar && !avatar.startsWith("/")}
        />
    );
}

// ── 게시글 카드 ──────────────────────────────────
function PostCard({ post, myId, onLike, onNavigate }: {
    post: GalleryPost; myId: string | null;
    onLike: (id: string) => void;
    onNavigate: (id: string) => void;
}) {
    const displayName = post.userNickname ?? post.userName;

    return (
        <div
            className="group rounded-2xl overflow-hidden transition-all duration-200 hover:shadow-md cursor-pointer"
            style={{ background: "#fff", border: "1px solid rgba(0,0,0,0.06)" }}
            onClick={() => onNavigate(post.id)}
        >
            {/* 이미지 */}
            <div className="relative w-full" style={{ paddingBottom: "100%", background: "#f5f5f5" }}>
                {post.images[0] && (
                    <Image src={post.images[0]} alt={post.themeName} fill className="object-cover" />
                )}
                {post.images.length > 1 && (
                    <div className="absolute top-2 right-2 w-5 h-5 rounded-full flex items-center justify-center"
                        style={{ background: "rgba(0,0,0,0.45)" }}>
                        <svg width="9" height="9" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/>
                        </svg>
                    </div>
                )}
            </div>

            {/* 하단 정보 */}
            <div className="px-3 py-2.5 flex items-center justify-between gap-2">
                {/* 프사 + 닉네임 + 시간 */}
                <div className="flex items-center gap-2 min-w-0">
                    <Link href={`/creator/${post.userId}`} onClick={(e) => e.stopPropagation()} className="shrink-0">
                        <Avatar avatar={post.userAvatar} name={displayName} role={post.userRole} size={22} />
                    </Link>
                    <Link
                        href={`/creator/${post.userId}`}
                        onClick={(e) => e.stopPropagation()}
                        className="text-[12px] font-medium truncate hover:underline"
                        style={{ color: "#78716c" }}
                    >
                        {displayName}
                    </Link>
                    <span className="text-[11px] shrink-0" style={{ color: "#d6d3d1" }}>{timeAgo(post.createdAt)}</span>
                </div>
                {/* 좋아요 + 댓글 */}
                <div className="flex items-center gap-2.5 shrink-0">
                    <button
                        onClick={(e) => { e.stopPropagation(); if (myId) onLike(post.id); }}
                        className="flex items-center gap-0.5 transition-opacity hover:opacity-60"
                        style={{ color: post.liked ? "#FF3B30" : "#c8c4c0" }}>
                        <svg width="13" height="13" viewBox="0 0 24 24" fill={post.liked ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
                        </svg>
                        <span className="text-[11px]">{post.likeCount}</span>
                    </button>
                    <div className="flex items-center gap-0.5" style={{ color: "#c8c4c0" }}>
                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                            <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/>
                        </svg>
                        <span className="text-[11px]">{post.commentCount}</span>
                    </div>
                </div>
            </div>
        </div>
    );
}

// ── 메인 페이지 ──────────────────────────────────
export default function GalleryPage() {
    const router = useRouter();
    const [posts, setPosts] = useState<GalleryPost[]>([]);
    const [sort, setSort] = useState<"latest" | "likes">("latest");
    const [loading, setLoading] = useState(true);
    const [myId, setMyId] = useState<string | null>(null);
    const [isLoggedIn, setIsLoggedIn] = useState(false);
    const [page, setPage] = useState(1);
    const [total, setTotal] = useState(0);

    useEffect(() => {
        fetch("/api/auth/session").then((r) => r.json()).then((d) => {
            if (d?.session) { setIsLoggedIn(true); setMyId(d.session.dbId ?? null); }
        }).catch(() => {});
    }, []);

    const fetchPosts = useCallback(async (p = 1, s = sort) => {
        setLoading(true);
        try {
            const res = await fetch(`/api/gallery?sort=${s}&page=${p}`);
            const data = await res.json() as { posts: GalleryPost[]; total: number };
            setPosts(p === 1 ? data.posts : (prev) => [...prev, ...data.posts]);
            setTotal(data.total);
        } finally {
            setLoading(false);
        }
    }, [sort]);

    useEffect(() => {
        setPage(1);
        fetchPosts(1, sort);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [sort]);

    const handleLike = async (postId: string) => {
        if (!myId) return;
        const res = await fetch(`/api/gallery/${postId}/like`, { method: "POST" });
        const data = await res.json() as { liked: boolean };
        setPosts((prev) => prev.map((p) =>
            p.id === postId ? { ...p, liked: data.liked, likeCount: p.likeCount + (data.liked ? 1 : -1) } : p
        ));
    };

    return (
        <div className="min-h-screen flex flex-col" style={{ backgroundColor: "#f3f3f3" }}>
            <Header />
            <div className="flex-1 max-w-[1200px] mx-auto w-full px-5 pt-12 pb-24">
                {/* 헤더 */}
                <div className="flex items-end justify-between mb-10">
                    <div>
                        <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-2" style={{ color: "#a8a29e" }}>Gallery</p>
                        <h1 className="text-[28px] font-bold tracking-tight" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>꾸미 갤러리</h1>
                        <p className="text-[14px] mt-1" style={{ color: "#78716c" }}>카꾸미로 만든 테마를 소개해보세요!</p>
                    </div>
                    {isLoggedIn && (
                        <button
                            onClick={() => router.push("/gallery/new")}
                            className="flex items-center gap-1.5 px-5 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-70"
                            style={{ background: "#1c1917", color: "#fafaf9" }}>
                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M12 5v14M5 12h14"/></svg>
                            테마 소개하기
                        </button>
                    )}
                </div>

                {/* 정렬 탭 */}
                <div className="flex items-center gap-1.5 mb-8">
                    {(["latest", "likes"] as const).map((s) => (
                        <button key={s} onClick={() => setSort(s)}
                            className="px-4 py-1.5 rounded-full text-[13px] font-medium transition-all duration-150"
                            style={{
                                backgroundColor: sort === s ? "rgb(74,123,247)" : "transparent",
                                color: sort === s ? "#fff" : "#78716c",
                                border: `1px solid ${sort === s ? "rgb(74,123,247)" : "#e7e5e4"}`,
                            }}>
                            {s === "latest" ? "최신순" : "좋아요순"}
                        </button>
                    ))}
                </div>

                {/* 그리드 */}
                {loading && posts.length === 0 ? (
                    <div className="flex justify-center items-center py-32">
                        <div className="w-6 h-6 rounded-full border-2 border-stone-200 border-t-stone-400 animate-spin" />
                    </div>
                ) : posts.length === 0 ? (
                    <div className="flex flex-col items-center gap-4 py-32">
                        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="#d6d3d1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18M9 21V9"/>
                        </svg>
                        <p className="text-[14px]" style={{ color: "#a8a29e" }}>아직 게시글이 없어요. 첫 번째로 소개해보세요!</p>
                    </div>
                ) : (
                    <div className="grid gap-4" style={{ gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))" }}>
                        {posts.map((post) => (
                            <PostCard key={post.id} post={post} myId={myId} onLike={handleLike} onNavigate={(id) => router.push(`/gallery/${id}`)} />
                        ))}
                    </div>
                )}

                {/* 더보기 */}
                {posts.length < total && !loading && (
                    <div className="flex justify-center mt-10">
                        <button onClick={() => { const next = page + 1; setPage(next); fetchPosts(next); }}
                            className="px-6 py-2 rounded-full text-[13px] font-medium transition-opacity hover:opacity-60"
                            style={{ border: "1px solid #e7e5e4", color: "#78716c" }}>
                            더 보기
                        </button>
                    </div>
                )}
            </div>
            <Footer />
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";

type Subscription = {
    id: string;
    status: string;
    amount: number;
    cardCompany?: string | null;
    cardNumber?: string | null;
    startedAt: string;
    nextBillingAt: string | null;
    cancelledAt: string | null;
};

function formatDate(dateStr: string | null) {
    if (!dateStr) return "-";
    const d = new Date(dateStr);
    return `${d.getFullYear()}. ${String(d.getMonth() + 1).padStart(2, "0")}. ${String(d.getDate()).padStart(2, "0")}`;
}

export default function SubscriptionInfoPage() {
    const router = useRouter();
    const [sub, setSub] = useState<Subscription | null>(null);
    const [loading, setLoading] = useState(true);
    const [cancelConfirm, setCancelConfirm] = useState(false);
    const [cancelling, setCancelling] = useState(false);
    const [toast, setToast] = useState("");

    const showToast = (msg: string) => {
        setToast(msg);
        setTimeout(() => setToast(""), 3000);
    };

    useEffect(() => {
        const load = async () => {
            try {
                const res = await fetch("/api/subscription");
                const data = await res.json() as { subscription: Subscription | null; payments?: unknown[]; role?: string | null };
                setSub(data.subscription);
            } catch { /* ignore */ } finally {
                setLoading(false);
            }
        };
        void load();
    }, []);

    const handleCancel = async () => {
        setCancelling(true);
        try {
            const res = await fetch("/api/subscription", { method: "DELETE" });
            const data = await res.json() as { ok?: boolean; error?: string };
            if (!res.ok) {
                showToast(data.error ?? "해지 처리 중 오류가 발생했습니다.");
            } else {
                showToast("구독이 해지됐어요. 기간 만료 전까지 Pro 혜택은 유지돼요.");
                setCancelConfirm(false);
                // 상태 갱신
                setSub(prev => prev ? { ...prev, status: "CANCELLED", cancelledAt: new Date().toISOString() } : prev);
                setTimeout(() => router.refresh(), 1000);
            }
        } finally {
            setCancelling(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center py-20">
                <div className="w-8 h-8 rounded-full border-4 border-orange-200 border-t-orange-400 animate-spin" />
            </div>
        );
    }

    return (
        <>
            {toast && (
                <div className="fixed top-5 left-1/2 -translate-x-1/2 z-50 px-5 py-2.5 rounded-xl text-[13px] font-medium shadow-lg"
                    style={{ background: "#18181b", color: "#fff" }}>
                    {toast}
                </div>
            )}

            <div className="flex items-end justify-between mb-8">
                <div>
                    <p className="text-[11px] font-semibold tracking-[0.12em] uppercase mb-1.5" style={{ color: "#a8a29e" }}>Subscription</p>
                    <h2 className="text-[22px] font-bold" style={{ color: "#1c1917", letterSpacing: "-0.02em" }}>결제 정보</h2>
                </div>
            </div>

            {!sub || sub.status?.toUpperCase() !== "ACTIVE" ? (
                /* 구독 없음 */
                <div className="flex flex-col items-center justify-center py-24 gap-5">
                    <div className="w-14 h-14 rounded-full flex items-center justify-center" style={{ background: "rgba(255,149,0,0.08)" }}>
                        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#FF9500" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="1" y="4" width="22" height="16" rx="2" ry="2"/><line x1="1" y1="10" x2="23" y2="10"/>
                        </svg>
                    </div>
                    <div className="text-center">
                        <p className="text-[16px] font-semibold mb-1" style={{ color: "#1c1917" }}>현재 구독 중인 요금제가 없어요</p>
                        <p className="text-[13px]" style={{ color: "#a8a29e" }}>Pro 플랜을 구독하면 더 많은 기능을 이용할 수 있어요.</p>
                    </div>
                    <button
                        onClick={() => router.push("/pricing")}
                        className="px-6 py-2.5 rounded-xl text-[13px] font-bold transition-all hover:brightness-110"
                        style={{ background: "linear-gradient(135deg, #FF9500, #FF6B00)", color: "#fff" }}>
                        Pro 구독하기
                    </button>
                </div>
            ) : (
                <div className="flex flex-col gap-0">
                    {/* 현재 요금제 */}
                    <div className="flex flex-col gap-4 pb-8">
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>사용 중인 요금제</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        <div className="flex items-center gap-3">
                            <span className="text-[15px] font-bold" style={{ color: "#1c1917" }}>Pro</span>
                            <span className="text-[11px] font-bold px-2 py-0.5 rounded-full" style={{ background: "rgba(255,149,0,0.1)", color: "#FF9500" }}>구독 중</span>
                        </div>
                        <p className="text-[13px]" style={{ color: "#78716c" }}>월 {sub.amount.toLocaleString()}원 · 자동 결제</p>
                    </div>

                    {/* 결제 수단 */}
                    <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>결제 수단</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        {sub.cardCompany || sub.cardNumber ? (
                            <div className="flex items-center gap-3">
                                <div className="flex items-center justify-center w-9 h-6 rounded-md" style={{ background: "rgba(0,0,0,0.06)" }}>
                                    <svg width="16" height="12" viewBox="0 0 24 16" fill="none">
                                        <rect x="0" y="0" width="24" height="16" rx="2" fill="#1c1c1e"/>
                                        <rect x="1" y="5" width="22" height="3" fill="rgba(255,255,255,0.15)"/>
                                    </svg>
                                </div>
                                <div>
                                    <p className="text-[14px] font-medium" style={{ color: "#1c1917" }}>
                                        {sub.cardCompany ?? "카드"} {sub.cardNumber ? `**** **** **** ${sub.cardNumber.slice(-4)}` : ""}
                                    </p>
                                </div>
                            </div>
                        ) : (
                            <p className="text-[13px]" style={{ color: "#a8a29e" }}>등록된 카드 정보가 없습니다.</p>
                        )}
                    </div>

                    {/* 등록일 / 다음 결제일 */}
                    <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>구독 정보</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        <div className="flex flex-col gap-3">
                            <div className="flex items-center justify-between">
                                <span className="text-[13px]" style={{ color: "#78716c" }}>구독 시작일</span>
                                <span className="text-[13px] font-medium" style={{ color: "#1c1917" }}>{formatDate(sub.startedAt)}</span>
                            </div>
                            <div className="flex items-center justify-between">
                                <span className="text-[13px]" style={{ color: "#78716c" }}>다음 결제일</span>
                                <span className="text-[13px] font-medium" style={{ color: "#1c1917" }}>{formatDate(sub.nextBillingAt)}</span>
                            </div>
                        </div>
                    </div>

                    {/* 구독 해지 */}
                    <div className="flex flex-col gap-4 pt-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>구독 관리</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>

                        {!cancelConfirm ? (
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-[14px] font-medium" style={{ color: "#1c1917" }}>구독 해지</p>
                                    <p className="text-[12px] mt-0.5" style={{ color: "#a8a29e" }}>해지해도 기간 만료 전까지 Pro 혜택은 유지돼요.</p>
                                </div>
                                <button
                                    onClick={() => setCancelConfirm(true)}
                                    className="text-[12px] font-medium px-4 py-2 rounded-xl transition-opacity hover:opacity-70"
                                    style={{ background: "rgba(255,59,48,0.08)", color: "#ff3b30" }}>
                                    해지하기
                                </button>
                            </div>
                        ) : (
                            <div className="rounded-2xl p-5 flex flex-col gap-4" style={{ background: "rgba(255,59,48,0.05)", border: "1px solid rgba(255,59,48,0.1)" }}>
                                <p className="text-[13px] font-medium" style={{ color: "#ff3b30" }}>정말 구독을 해지하시겠어요?</p>
                                <p className="text-[12px]" style={{ color: "#78716c" }}>
                                    해지 후에도 <strong>{formatDate(sub.nextBillingAt)}</strong>까지는 Pro 혜택이 유지됩니다.
                                    이후에는 무료 플랜으로 전환됩니다.
                                </p>
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => setCancelConfirm(false)}
                                        className="flex-1 py-2.5 rounded-xl text-[13px] font-medium transition-opacity hover:opacity-70"
                                        style={{ background: "rgba(0,0,0,0.06)", color: "#78716c" }}>
                                        취소
                                    </button>
                                    <button
                                        onClick={handleCancel}
                                        disabled={cancelling}
                                        className="flex-1 py-2.5 rounded-xl text-[13px] font-semibold transition-opacity hover:opacity-70 disabled:opacity-40"
                                        style={{ background: "rgba(255,59,48,0.12)", color: "#ff3b30" }}>
                                        {cancelling ? "처리 중..." : "해지 확인"}
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </>
    );
}

