                /* 구독 없음 */
                <div className="flex flex-col items-center justify-center py-24 gap-5">
                    <div className="w-14 h-14 rounded-full flex items-center justify-center" style={{ background: "rgba(255,149,0,0.08)" }}>
                        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#FF9500" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                            <rect x="1" y="4" width="22" height="16" rx="2" ry="2"/><line x1="1" y1="10" x2="23" y2="10"/>
                        </svg>
                    </div>
                    <div className="text-center">
                        <p className="text-[16px] font-semibold mb-1" style={{ color: "#1c1917" }}>현재 구독 중인 요금제가 없어요</p>
                        <p className="text-[13px]" style={{ color: "#a8a29e" }}>Pro 플랜을 구독하면 더 많은 기능을 이용할 수 있어요.</p>
                    </div>
                    <button
                        onClick={() => router.push("/pricing")}
                        className="px-6 py-2.5 rounded-xl text-[13px] font-bold transition-all hover:brightness-110"
                        style={{ background: "linear-gradient(135deg, #FF9500, #FF6B00)", color: "#fff" }}>
                        Pro 구독하기
                    </button>
                </div>
            ) : (
                <div className="flex flex-col gap-0">
                    {/* 현재 요금제 */}
                    <div className="flex flex-col gap-4 pb-8">
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>사용 중인 요금제</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        <div className="flex items-center gap-3">
                            <span className="text-[15px] font-bold" style={{ color: "#1c1917" }}>Pro</span>
                            <span className="text-[11px] font-bold px-2 py-0.5 rounded-full" style={{ background: "rgba(255,149,0,0.1)", color: "#FF9500" }}>구독 중</span>
                        </div>
                        <p className="text-[13px]" style={{ color: "#78716c" }}>월 {sub.amount.toLocaleString()}원 · 자동 결제</p>
                    </div>

                    {/* 결제 수단 */}
                    <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>결제 수단</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        {sub.cardCompany || sub.cardNumber ? (
                            <div className="flex items-center gap-3">
                                <div className="flex items-center justify-center w-9 h-6 rounded-md" style={{ background: "rgba(0,0,0,0.06)" }}>
                                    <svg width="16" height="12" viewBox="0 0 24 16" fill="none">
                                        <rect x="0" y="0" width="24" height="16" rx="2" fill="#1c1c1e"/>
                                        <rect x="1" y="5" width="22" height="3" fill="rgba(255,255,255,0.15)"/>
                                    </svg>
                                </div>
                                <div>
                                    <p className="text-[14px] font-medium" style={{ color: "#1c1917" }}>
                                        {sub.cardCompany ?? "카드"} {sub.cardNumber ? `**** **** **** ${sub.cardNumber.slice(-4)}` : ""}
                                    </p>
                                </div>
                            </div>
                        ) : (
                            <p className="text-[13px]" style={{ color: "#a8a29e" }}>등록된 카드 정보가 없습니다.</p>
                        )}
                    </div>

                    {/* 등록일 / 다음 결제일 */}
                    <div className="flex flex-col gap-4 py-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>구독 정보</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>
                        <div className="flex flex-col gap-3">
                            <div className="flex items-center justify-between">
                                <span className="text-[13px]" style={{ color: "#78716c" }}>구독 시작일</span>
                                <span className="text-[13px] font-medium" style={{ color: "#1c1917" }}>{formatDate(sub.startedAt)}</span>
                            </div>
                            <div className="flex items-center justify-between">
                                <span className="text-[13px]" style={{ color: "#78716c" }}>다음 결제일</span>
                                <span className="text-[13px] font-medium" style={{ color: "#1c1917" }}>{formatDate(sub.nextBillingAt)}</span>
                            </div>
                        </div>
                    </div>

                    {/* 구독 해지 */}
                    <div className="flex flex-col gap-4 pt-8" style={{ borderTop: "1px solid #e7e5e4" }}>
                        <div className="flex items-center gap-3 mb-1">
                            <span className="text-[11px] font-semibold tracking-wide uppercase" style={{ color: "#a8a29e" }}>구독 관리</span>
                            <div className="flex-1 h-px" style={{ backgroundColor: "#e7e5e4" }} />
                        </div>

                        {!cancelConfirm ? (
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-[14px] font-medium" style={{ color: "#1c1917" }}>구독 해지</p>
                                    <p className="text-[12px] mt-0.5" style={{ color: "#a8a29e" }}>해지해도 기간 만료 전까지 Pro 혜택은 유지돼요.</p>
                                </div>
                                <button
                                    onClick={() => setCancelConfirm(true)}
                                    className="text-[12px] font-medium px-4 py-2 rounded-xl transition-opacity hover:opacity-70"
                                    style={{ background: "rgba(255,59,48,0.08)", color: "#ff3b30" }}>
                                    해지하기
                                </button>
                            </div>
                        ) : (
                            <div className="rounded-2xl p-5 flex flex-col gap-4" style={{ background: "rgba(255,59,48,0.05)", border: "1px solid rgba(255,59,48,0.1)" }}>
                                <p className="text-[13px] font-medium" style={{ color: "#ff3b30" }}>정말 구독을 해지하시겠어요?</p>
                                <p className="text-[12px]" style={{ color: "#78716c" }}>
                                    해지 후에도 <strong>{formatDate(sub.nextBillingAt)}</strong>까지는 Pro 혜택이 유지됩니다.
                                    이후에는 무료 플랜으로 전환됩니다.
                                </p>
                                <div className="flex gap-2">
                                    <button
                                        onClick={() => setCancelConfirm(false)}
                                        className="flex-1 py-2.5 rounded-xl text-[13px] font-medium transition-opacity hover:opacity-70"
                                        style={{ background: "rgba(0,0,0,0.06)", color: "#78716c" }}>
                                        취소
                                    </button>
                                    <button
                                        onClick={handleCancel}
                                        disabled={cancelling}
                                        className="flex-1 py-2.5 rounded-xl text-[13px] font-semibold transition-opacity hover:opacity-70 disabled:opacity-40"
                                        style={{ background: "rgba(255,59,48,0.12)", color: "#ff3b30" }}>
                                        {cancelling ? "처리 중..." : "해지 확인"}
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </>
    );
}

import { cookies } from "next/headers";
import { createHmac } from "crypto";
import { Suspense } from "react";
import Header from "../components/Header";
import { prisma } from "@/lib/prisma";
import MyPageClient from "./MyPageClient";

const SESSION_COOKIE_NAME = "kakkumi_session";

function verifySession(token: string, secret: string) {
    const [payloadB64, signature] = token.split(".");
    if (!payloadB64 || !signature) return null;
    const json = Buffer.from(payloadB64, "base64url").toString("utf8");
    const expectedSignature = createHmac("sha256", secret).update(json).digest("base64url");
    if (signature !== expectedSignature) return null;
    return JSON.parse(json) as Record<string, unknown>;
}

async function getSession() {
    try {
        const sessionSecret = process.env.KAKAO_SESSION_SECRET;
        if (!sessionSecret) return null;
        const cookieStore = await cookies();
        const sessionCookie = cookieStore.get(SESSION_COOKIE_NAME);
        if (!sessionCookie) return null;
        const session = verifySession(sessionCookie.value, sessionSecret);
        return session as { name?: string | null; nickname?: string | null; image?: string | null; avatarUrl?: string | null; id?: string | null; dbId?: string | null; email?: string | null; role?: string | null } | null;
    } catch {
        return null;
    }
}

export default async function MyPage() {
    const session = await getSession();

    let purchasedCount = 0;
    let createdAt: string | null = null;
    let credit = 0;
    let dbAvatarUrl: string | null = null;
    let isPro = false;

        purchasedCount = await prisma.purchase.count({
            where: { buyerId: session.dbId, status: "COMPLETED" },
        });
        try {
            const rows = await prisma.$queryRaw<{ createdAt: Date; credit: number; avatarUrl: string | null }[]>`
                SELECT "createdAt", credit, "avatarUrl" FROM "User" WHERE id = ${session.dbId} LIMIT 1
            `;
            createdAt = rows[0]?.createdAt?.toISOString() ?? null;
            credit = rows[0]?.credit ?? 0;
            dbAvatarUrl = rows[0]?.avatarUrl ?? null;
        } catch {
            createdAt = null;
        }

        // 구독 상태 직접 확인 (캐시 없이, pricing/page.tsx와 동일한 방식)
            items: [{ label: "회원 정보" }, { label: "알림 설정" }],
        },
        {
            category: "테마",
            items: [{ label: "업로드 테마" }, { label: "구매 테마" }],
        },
        {
            category: "쇼핑",
            items: [
                { label: "리뷰" }, { label: "적립금" }, { label: "작성 가능한 후기" },
                { label: "주문 내역" }, { label: "취소/환불 내역" }, { label: "좋아요" }, { label: "팔로우" },
            ],
        },
        {
            category: "수익",
            items: [{ label: "정산 내역" }, { label: "판매 통계" }, { label: "정산 계좌" }],
        },
        {
            category: "계정",
            items: [{ label: "결제 정보" }, { label: "결제 내역" }, { label: "회원 탈퇴" }],
        },
    ];

    const sessionWithAvatar = session ? { ...session, avatarUrl: dbAvatarUrl } : null;

    return (
        <div
            className="min-h-screen flex flex-col mac-scroll"
            style={{
                backgroundColor: "#f3f3f3",
            }}
        >
            <Header />
            <Suspense fallback={<div className="flex-1 flex items-center justify-center py-24"><div className="w-10 h-10 rounded-full border-4 border-gray-200 border-t-gray-500 animate-spin" /></div>}>
                <MyPageClient
                    session={sessionWithAvatar}
                    purchasedCount={purchasedCount}
                    sidebarMenus={sidebarMenus}
                    createdAt={createdAt}
                    credit={credit}
                    isPro={isPro}
                />
            </Suspense>
        </div>
    );
}

import { cookies } from "next/headers";
import { createHmac } from "crypto";
import { Suspense } from "react";
import Header from "../components/Header";
import { prisma } from "@/lib/prisma";
import MyPageClient from "./MyPageClient";

export const dynamic = "force-dynamic";

const SESSION_COOKIE_NAME = "kakkumi_session";

function verifySession(token: string, secret: string) {
    const [payloadB64, signature] = token.split(".");
    if (!payloadB64 || !signature) return null;
    const json = Buffer.from(payloadB64, "base64url").toString("utf8");
    const expectedSignature = createHmac("sha256", secret).update(json).digest("base64url");
    if (signature !== expectedSignature) return null;
    return JSON.parse(json) as Record<string, unknown>;
}

async function getSession() {
    try {
        const sessionSecret = process.env.KAKAO_SESSION_SECRET;
        if (!sessionSecret) return null;
        const cookieStore = await cookies();
        const sessionCookie = cookieStore.get(SESSION_COOKIE_NAME);
        if (!sessionCookie) return null;
        const session = verifySession(sessionCookie.value, sessionSecret);
        return session as { name?: string | null; nickname?: string | null; image?: string | null; avatarUrl?: string | null; id?: string | null; dbId?: string | null; email?: string | null; role?: string | null } | null;
    } catch {
        return null;
    }
}

export default async function MyPage() {
    const session = await getSession();

    let purchasedCount = 0;
    let createdAt: string | null = null;
    let credit = 0;
    let dbAvatarUrl: string | null = null;
    let isPro = false;

    if (session?.dbId) {
        purchasedCount = await prisma.purchase.count({
            where: { buyerId: session.dbId, status: "COMPLETED" },
        });
        try {
            const rows = await prisma.$queryRaw<{ createdAt: Date; credit: number; avatarUrl: string | null }[]>`
                SELECT "createdAt", credit, "avatarUrl" FROM "User" WHERE id = ${session.dbId} LIMIT 1
            `;
            createdAt = rows[0]?.createdAt?.toISOString() ?? null;
            credit = rows[0]?.credit ?? 0;
            dbAvatarUrl = rows[0]?.avatarUrl ?? null;
        } catch {
            createdAt = null;
        }

        // 구독 상태 직접 확인 (CREATOR 포함 모든 role 체크)
        const role = session.role ?? "USER";
        if (role === "ADMIN") {
            isPro = true;
        } else {
            // USER, CREATOR 모두 PRO 구독 여부 확인
            const sub = await prisma.subscription.findUnique({ where: { userId: session.dbId } });
            isPro = !!sub && String(sub.status).toUpperCase() === "ACTIVE";
        }
    }

    const sidebarMenus = [
        {
            category: "정보",
            items: [{ label: "회원 정보" }, { label: "알림 설정" }],
        },
        {
            category: "테마",
            items: [{ label: "업로드 테마" }, { label: "구매 테마" }],
        },
        {
            category: "쇼핑",
            items: [
                { label: "리뷰" }, { label: "적립금" }, { label: "작성 가능한 후기" },
                { label: "주문 내역" }, { label: "취소/환불 내역" }, { label: "좋아요" }, { label: "팔로우" },
            ],
        },
        {
            category: "수익",
            items: [{ label: "정산 내역" }, { label: "판매 통계" }, { label: "정산 계좌" }],
        },
        {
            category: "계정",
            items: [{ label: "결제 정보" }, { label: "결제 내역" }, { label: "회원 탈퇴" }],
        },
    ];

    const sessionWithAvatar = session ? { ...session, avatarUrl: dbAvatarUrl } : null;

    return (
        <div
            className="min-h-screen flex flex-col mac-scroll"
            style={{
                backgroundColor: "#f3f3f3",
            }}
        >
            <Header />
            <Suspense fallback={<div className="flex-1 flex items-center justify-center py-24"><div className="w-10 h-10 rounded-full border-4 border-gray-200 border-t-gray-500 animate-spin" /></div>}>
                <MyPageClient
                    session={sessionWithAvatar}
                    purchasedCount={purchasedCount}
                    sidebarMenus={sidebarMenus}
                    createdAt={createdAt}
                    credit={credit}
                    isPro={isPro}
                />
            </Suspense>
        </div>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { validateNickname } from "@/lib/nickname";
import Image from "next/image";

export default function OnboardingPage() {
    const router = useRouter();
    const [nickname, setNickname] = useState("");
    const [error, setError] = useState("");
    const [checkStatus, setCheckStatus] = useState<"idle" | "checking" | "available" | "taken">("idle");
    const [saving, setSaving] = useState(false);
    const [referralCode, setReferralCode] = useState("");
    const [referralMsg, setReferralMsg] = useState<{ ok: boolean; text: string } | null>(null);
    const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // 프로필 이미지 상태
    const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
    const [avatarError, setAvatarError] = useState("");
    const fileInputRef = useRef<HTMLInputElement>(null);

    // 입력할 때마다 실시간 중복 체크 (debounce)
    useEffect(() => {
        if (debounceRef.current) clearTimeout(debounceRef.current);

        debounceRef.current = setTimeout(() => {
            const validationError = validateNickname(nickname);
            if (validationError) {
                setError(validationError);
                setCheckStatus("idle");
                return;
            }

            setError("");
            setCheckStatus("checking");

            fetch(`/api/user/nickname/check?nickname=${encodeURIComponent(nickname)}`)
                .then((res) => res.json())
                .then((data: { available: boolean; error?: string }) => {
                    if (data.error) {
                        setError(data.error);
                        setCheckStatus("idle");
                    } else {
                        setCheckStatus(data.available ? "available" : "taken");
                        if (!data.available) setError("이미 사용 중인 닉네임입니다.");
                    }
                })
                .catch(() => setCheckStatus("idle"));
        }, 500);
    }, [nickname]);

    const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        if (!file.type.startsWith("image/")) {
            setAvatarError("이미지 파일만 업로드할 수 있습니다.");
            return;
        }
        if (file.size > 2 * 1024 * 1024) {
            setAvatarError("이미지 크기는 2MB 이하여야 합니다.");
            return;
        }
        setAvatarError("");
        const reader = new FileReader();
        reader.onload = (ev) => {
            setAvatarPreview(ev.target?.result as string);
        };
        reader.readAsDataURL(file);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (checkStatus !== "available" || saving) return;

        setSaving(true);

        // 1) 닉네임 + 추천인 코드 저장
        const res = await fetch("/api/user/nickname", {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ nickname, referralCode: referralCode.trim() || null }),
        });
        const data = await res.json() as { nickname?: string; error?: string };

        if (!res.ok) {
            const errorMsg = data.error ?? "저장 실패";
            if (errorMsg.includes("닉네임")) {
                setReferralMsg({ ok: false, text: errorMsg });
            } else {
                setError(errorMsg);
            }
            setSaving(false);
            return;
        }

        // 2) 프로필 이미지 저장 (선택한 경우만)
        if (avatarPreview) {
            await fetch("/api/user/avatar", {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ avatarUrl: avatarPreview }),
            });
        }

        setSaving(false);
        router.push("/");
    };

    return (
        <div
            className="min-h-screen flex flex-col items-center justify-center px-4"
            style={{
                backgroundColor: "#f3f3f3",
            }}
        >
            <div
                className="w-full max-w-[440px] flex flex-col gap-7 p-10 rounded-[28px]"
                style={{
                    background: "rgba(255,255,255,0.85)",
                    backdropFilter: "blur(20px)",
                    boxShadow: "0 8px 40px rgba(0,0,0,0.08)",
                    border: "1px solid rgba(255,255,255,0.9)",
                }}
            >
                {/* 로고 */}
                <div className="flex flex-col items-center gap-3">
                    <Image src="/카꾸미.png" alt="카꾸미" width={52} height={52} className="rounded-[14px]" />
                    <div className="flex flex-col items-center gap-1">
                        <h1 className="text-[22px] font-extrabold" style={{ color: "#1c1c1e", fontFamily: "'ChosunIlboMyungjo', serif" }}>
                            카꾸미에 오신 걸 환영해요!
                        </h1>
                        <p className="text-[13px] text-center leading-relaxed" style={{ color: "#8e8e93" }}>
                            프로필을 설정하고 시작해보세요.
                        </p>
                    </div>
                </div>

                {/* 입력 폼 */}
                <form onSubmit={handleSubmit} className="flex flex-col gap-6">

                    {/* 프로필 이미지 (선택) */}
                    <div className="flex flex-col items-center gap-3">
                        <button
                            type="button"
                            onClick={() => fileInputRef.current?.click()}
                            className="relative group w-24 h-24 rounded-full overflow-hidden flex items-center justify-center transition-all hover:opacity-90 active:scale-95"
                            style={{ background: avatarPreview ? 'transparent' : 'rgba(195,195,195,0.5)', boxShadow: "0 2px 12px rgba(0,0,0,0.1)" }}
                        >
                            {avatarPreview ? (
                                <Image src={avatarPreview} alt="프로필 미리보기" fill className="object-cover" unoptimized />
                            ) : (
                                <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="#3A1D1D" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round">
                                    <circle cx="12" cy="8" r="4" />
                                    <path d="M4 20c0-4 3.6-7 8-7s8 3 8 7" />
                                </svg>
                            )}
                            {/* 오버레이 */}
                            <div
                                className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                                style={{ background: "rgba(0,0,0,0.35)" }}
                            >
                                <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                    <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
                                    <polyline points="17 8 12 3 7 8" />
                                    <line x1="12" y1="3" x2="12" y2="15" />
                                </svg>
                            </div>
                        </button>
                        <input
                            ref={fileInputRef}
                            type="file"
                            accept="image/*"
                            className="hidden"
                            onChange={handleAvatarChange}
                        />
                        <div className="flex flex-col items-center gap-0.5">
                            <span className="text-[12px] font-medium" style={{ color: "#3a3a3c" }}>
                                프로필 사진 <span className="text-[11px]" style={{ color: "#8e8e93" }}>(선택)</span>
                            </span>
                            {avatarPreview && (
                                <button
                                    type="button"
                                    onClick={() => { setAvatarPreview(null); if (fileInputRef.current) fileInputRef.current.value = ""; }}
                                    className="text-[11px] transition-all hover:opacity-70"
                                    style={{ color: "#ff3b30" }}
                                >
                                    사진 제거
                                </button>
                            )}
                            {avatarError && <p className="text-[11px]" style={{ color: "#ff3b30" }}>{avatarError}</p>}
                        </div>
                    </div>

                    {/* 닉네임 */}
                    <div className="flex flex-col gap-3">
                        {/* 규칙 안내 */}
                        <div
                            className="flex flex-col gap-1.5 px-4 py-3 rounded-[12px] text-[12px] leading-relaxed"
                            style={{ background: "rgba(74,123,247,0.07)", color: "#3a5a8a" }}
                        >
                            <p className="font-semibold">닉네임 규칙</p>
                            <ul className="flex flex-col gap-0.5 list-disc list-inside" style={{ color: "#48484a" }}>
                                <li>2~10자 이내</li>
                                <li>한글, 영문, 숫자 사용 가능</li>
                                <li>특수문자 불가</li>
                                <li>숫자만으로는 설정 불가</li>
                            </ul>
                        </div>

                        <div className="flex flex-col gap-1.5">
                            <label className="text-[12px] font-semibold" style={{ color: "#3a3a3c" }}>
