                                            <path d="M20 6L9 17l-5-5" />
                                        </svg>
                                    )}
                                    {checkStatus === "taken" && (
                                        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#ff3b30" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                            <line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" />
