                            <span className="text-[18px] font-medium mb-2" style={{ color: "rgba(255,255,255,0.5)" }}>원 / 월</span>
                        </div>
                        <p className="text-[13px]" style={{ color: "rgba(255,255,255,0.45)" }}>제한 없이 마음껏 테마를 만들어보세요</p>
                    </div>

                    <div className="flex flex-col gap-3">
                        {PRO_FEATURES.map((f) => (
